  getById: (id: number) =>
    apiService.get<InventoryResponse>(`/inventory/${id}`),

  start: (id: number) =>
    apiService.patch<void>(`/inventory/${id}/start`),

  close: (id: number) =>
    apiService.patch<void>(`/inventory/${id}/close`),

