// ═══════════════════════════════════════════════════════════════════════════════
// DEPRECIATION
// ═══════════════════════════════════════════════════════════════════════════════
export const depreciationApi = {
  getByAsset: (assetId: number) =>
    apiService.get<AssetDepreciation>(`/assets/${assetId}/depreciation`),

  getPortfolio: () =>
