// ═══════════════════════════════════════════════════════════════════════════════
// AUDIT
// ═══════════════════════════════════════════════════════════════════════════════
export const auditApi = {
  list: (params?: PageParams) =>
    apiService.get<AuditEvent[]>('/audit', { params }),

  byUser: (userId: number, params?: PageParams) =>
    apiService.get<AuditEvent[]>(`/audit/user/${userId}`, { params }),

  byType: (type: string, params?: PageParams) =>
    apiService.get<AuditEvent[]>(`/audit/type/${type}`, { params }),

  byTarget: (targetType: string, targetId: number, params?: PageParams) =>
    apiService.get<AuditEvent[]>('/audit/target', {
      params: { targetType, targetId, ...params },
    }),

  byPeriod: (organizationId: number, start: string, end: string, params?: PageParams) =>
    apiService.get<AuditEvent[]>('/audit/period', {
      params: { organizationId, start, end, ...params },
    }),

  lastByTarget: (targetType: string, targetId: number) =>
    apiService.get<AuditEvent>('/audit/target/last', {
      params: { targetType, targetId },
    }),
}

// ═══════════════════════════════════════════════════════════════════════════════
// EXPORT
// ═══════════════════════════════════════════════════════════════════════════════
export const exportApi = {
  downloadAssets: async (startDate?: string, endDate?: string) => {
    const res = await api.get<Blob>('/export/assets', {
      responseType: 'blob',
      params: { startDate, endDate },
    })
    triggerDownload(res.data, 'ativos.csv')
  },

  downloadMaintenance: async (startDate?: string, endDate?: string) => {
    const res = await api.get<Blob>('/export/maintenance', {
      responseType: 'blob',
      params: { startDate, endDate },
    })
    triggerDownload(res.data, 'manutencoes.csv')
  },

  downloadAudit: async (startDate?: string, endDate?: string) => {
    const res = await api.get<Blob>('/export/audit', {
      responseType: 'blob',
      params: { startDate, endDate },
    })
    triggerDownload(res.data, 'auditoria.csv')
  },
}

function triggerDownload(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = filename
  a.click()
  setTimeout(() => URL.revokeObjectURL(url), 100)
}

// ═══════════════════════════════════════════════════════════════════════════════
// DASHBOARD
// ═══════════════════════════════════════════════════════════════════════════════
export const dashboardApi = {
  executive: () =>
    apiService.get<ExecutiveDashboard>('/api/dashboard/executive'),

  unit: () =>
    apiService.get<UnitDashboard>('/api/dashboard/unit'),

  personal: () =>
    apiService.get<PersonalDashboard>('/api/dashboard/personal'),
}

import { chromium } from 'playwright'

(async () => {
  const browser = await chromium.launch({ headless: true })
  const page = await browser.newPage()

  try {
    await page.goto('http://localhost:5173/login', { waitUntil: 'domcontentloaded' })

    for (let i = 0; i < 5; i++) {
      await page.waitForTimeout(1000)
      const count = await page.locator('[data-testid]').count()
      const injectionReady = await page.evaluate(() => (window as any).__testIdInjectionReady)
      console.log(`Tempo: ${(i+1)*1000}ms - Test IDs: ${count}, Ready: ${injectionReady}`)
      if (count > 0) break
    }

  } finally {
    await browser.close()
  }
})()

import { Then } from '@cucumber/cucumber';
import { expect } from '@playwright/test';
import { CustomWorld } from '../../support/world';
import { E2E_ASSETS, findAssetRow, searchAsset } from './helpers';

Then('não devo ver o botão {string}', async function (this: CustomWorld, label: string) {
  const buttonTestIds: Record<string, string> = {
    'Novo Ativo': 'asset-new-btn',
    'Exportar CSV': 'asset-export-btn',
  };

  const testId = buttonTestIds[label];
  if (testId) {
    await expect(this.page.getByTestId(testId)).toBeHidden();
    return;
  }

  await expect(this.page.getByRole('button', { name: label })).toBeHidden();
});

Then('não devo ver o botão {string} na lista', async function (this: CustomWorld, label: string) {
  await expect(this.page.locator(`[title="${label}"]`)).toBeHidden();
});

Then('devo ver o botão {string}', async function (this: CustomWorld, label: string) {
  await expect(this.page.getByRole('button', { name: label })).toBeVisible({ timeout: 10000 });
});

Then('devo ver o botão de aposentar no primeiro ativo disponível', async function (this: CustomWorld) {
  const row = await findAssetRow(this, E2E_ASSETS.availableFilter);
  const btn = row.getByTestId('asset-action-retire');
  await expect(btn).toBeVisible({ timeout: 15000 });
});

Then('o download do arquivo deve ser iniciado', async function (this: CustomWorld) {
  const downloadPromise = this.page.waitForEvent('download');
  const exportBtn = this.page.getByTestId('asset-export-btn');
  await expect(exportBtn).toBeVisible({ timeout: 15000 });
  await exportBtn.click();
  const download = await downloadPromise;
  expect(download.suggestedFilename()).toMatch(/\.(csv|xlsx?)$/i);
});

import { Given } from '@cucumber/cucumber';
import { expect } from '@playwright/test';
import { CustomWorld } from '../../support/world';
import { CREDENTIALS } from './helpers';

