import { useEffect } from 'react'
import { Navigate } from 'react-router-dom'
import type { ReactNode } from 'react'
import { useAuth } from '../context/AuthContext'
import type { UserRole } from '../types'
import { tokenService } from '../utils/token'

interface Props {
  children: ReactNode
  roles?: UserRole[]
}

// ─────────────────────────────────────────────────────────
// Loading Component 
// ─────────────────────────────────────────────────────────
function FullScreenLoader() {
  return (
    <div className="flex items-center justify-center h-screen bg-[#f0f2f5]">
      <div className="flex flex-col items-center gap-3 text-slate-400">
        <div className="w-7 h-7 border-[2.5px] border-slate-300 border-t-blue-600 rounded-full animate-spin" />
        <span className="text-[13px]">Carregando...</span>
      </div>
    </div>
  )
}

export default function ProtectedRoute({ children, roles }: Props) {
  const { isAuthenticated, user, authStep } = useAuth()

  const hasToken = typeof window !== 'undefined' && !!tokenService.getAccess()

  // ─────────────────────────────────────────────────────────
  // MFA FLOW 
  // ─────────────────────────────────────────────────────────
  if (authStep === 'mfa') return null

  // ─────────────────────────────────────────────────────────
  // REHYDRATE 
  // ─────────────────────────────────────────────────────────
  if (!isAuthenticated && hasToken) {
    return <FullScreenLoader />
  }

  // ─────────────────────────────────────────────────────────
  // NOT AUTHENTICATED
  // ─────────────────────────────────────────────────────────
  if (!isAuthenticated) {
    return <Navigate to="/login" replace />
  }

  // ─────────────────────────────────────────────────────────
  // ROLE VALIDATION
  // ─────────────────────────────────────────────────────────
  if (roles && (!user || !roles.includes(user.role))) {
    return <Navigate to="/dashboard" replace />
  }

  // ─────────────────────────────────────────────────────────
  // OK
  // ─────────────────────────────────────────────────────────
  return <>{children}</>
}

import { useState, useCallback, useRef } from 'react'
import { userApi } from '../api'
import type { UserResponse, Page } from '../types'

export function useUsers() {
  const [page, setPage] = useState<Page<UserResponse> | null>(null)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [activeCount, setActiveCount] = useState(0)
  const [pendingCount, setPendingCount] = useState(0)

  const loadingRef = useRef(false)

  const load = useCallback(async (currentPage: number) => {
    if (loadingRef.current) return

    loadingRef.current = true
    setLoading(true)
    setError('')

    try {
      const [p, active, pending] = await Promise.all([
        userApi.list({ page: currentPage, size: 20, sort: 'id,desc' }),
        userApi.list({ size: 1, status: 'ACTIVE' }),
        userApi.list({ size: 1, status: 'PENDING_ACTIVATION' }),
      ])

      setPage(p)
      setActiveCount(active?.totalElements ?? 0)
      setPendingCount(pending?.totalElements ?? 0)
    } catch (e: any) {
      setError(
        e?.response?.data?.error?.message ??
        e?.response?.data?.message ??
        'Erro ao carregar usuários'
      )
    } finally {
      setLoading(false)
      loadingRef.current = false
    }
  }, [])

  return {
    page,
    loading,
    error,
    activeCount,
    pendingCount,
    load,
  }
}

