  const urlAssignedUserId = searchParams.get('assignedUserId') ? Number(searchParams.get('assignedUserId')) : undefined
  const urlStatus = searchParams.get('status') as AssetStatus | null
  const urlType = searchParams.get('type') as AssetType | null
  const insuranceMode = searchParams.get('insurance') === 'expiring'

  const initialStatus: AssetStatus | 'ALL' =
    urlStatus && VALID_STATUSES.includes(urlStatus) ? urlStatus : 'ALL'

  const initialType: AssetType | 'ALL' =
    urlType && ASSET_TYPE_OPTIONS.some(t => t.value === urlType) ? urlType : 'ALL'

  const effectiveUnitId = urlUnitId ?? (!isAdmin && isGestor ? user?.unitId : undefined)
  const effectiveAssignedUserId = urlAssignedUserId ?? (!isAdmin && !isGestor ? user?.userId : undefined)

  const [currentPage, setCurrentPage] = useState(0)
  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState<AssetStatus | 'ALL'>(initialStatus)
  const [typeFilter, setTypeFilter] = useState<AssetType | 'ALL'>(initialType)
  const [actionError, setActionError] = useState('')

  const [units, setUnits] = useState<UnitResponse[]>([])
  const [users, setUsers] = useState<UserResponse[]>([])

  // Mapa assetId → seguro a vencer (só carregado no modo insurance)
  const [expiringMap, setExpiringMap] = useState<Map<number, AssetInsurance>>(new Map())
  const [expiringAssetIds, setExpiringAssetIds] = useState<Set<number>>(new Set())

  const [showCreate, setShowCreate] = useState(false)
  const [createForm, setCreateForm] = useState<{ type: AssetType | ''; model: string; unitId: string }>({ type: '', model: '', unitId: '' })

  const [showAssign, setShowAssign] = useState<AssetResponse | null>(null)
  const [assignUserId, setAssignUserId] = useState('')

  const [showTransfer, setShowTransfer] = useState<AssetResponse | null>(null)
  const [transferForm, setTransferForm] = useState({ toUnitId: '', reason: '' })

  const [showMaint, setShowMaint] = useState<AssetResponse | null>(null)
  const [maintDesc, setMaintDesc] = useState('')
  const [maintCost, setMaintCost] = useState('')

  const [showRetire, setShowRetire] = useState<AssetResponse | null>(null)

  const [saving, setSaving] = useState(false)

  // Carrega seguros a vencer quando no modo insurance
  useEffect(() => {
    if (!insuranceMode) return
    insuranceApi.getExpiring(30)
      .then((list) => {
        const map = new Map<number, AssetInsurance>()
        const ids = new Set<number>()
        list.forEach((ins) => {
          map.set(ins.assetId, ins)
          ids.add(ins.assetId)
        })
        setExpiringMap(map)
        setExpiringAssetIds(ids)
      })
      .catch(console.error)
  }, [insuranceMode])

  const load = useCallback(() => {
    assets.load({
      page: currentPage,
      size: 10,
      sort: 'id,desc',
      ...(statusFilter !== 'ALL' ? { status: statusFilter } : {}),
      ...(typeFilter !== 'ALL' ? { type: typeFilter } : {}),
      ...(search ? { search } : {}),
      ...(effectiveUnitId ? { unitId: effectiveUnitId } : {}),
      ...(effectiveAssignedUserId ? { assignedUserId: effectiveAssignedUserId } : {}),
    })
  }, [currentPage, statusFilter, search, effectiveUnitId, effectiveAssignedUserId, typeFilter])

  useEffect(() => { load() }, [load])

  useEffect(() => {
    userApi.list({ size: 200, status: 'ACTIVE' })
      .then((p) => setUsers(Array.isArray(p?.content) ? p.content : []))
      .catch(console.error)
  }, [])

  useEffect(() => {
    const orgId = user?.organizationId
    if (!orgId) return
    unitApi.listByOrg(orgId)
      .then((list) => {
        const active = Array.isArray(list) ? list.filter(u => u.status === 'ACTIVE') : []
        setUnits(isGestor && user?.unitId ? active.filter(u => u.id === user.unitId) : active)
      })
      .catch(console.error)
  }, [user?.organizationId])

  const reload = () => load()

  const handleCreate = async () => {
    if (!user || !createForm.model || !createForm.type || !createForm.unitId) return
    setSaving(true); setActionError('')
    try {
      await assets.create(user.organizationId, {
        type: createForm.type,
        model: createForm.model,
        unitId: Number(createForm.unitId),
      })
      setShowCreate(false)
      setCreateForm({ type: '', model: '', unitId: '' })
      reload()
    } catch (e: any) {
      setActionError(e?.response?.data?.message ?? 'Erro ao criar ativo')
    } finally { setSaving(false) }
  }

  const handleAssign = async () => {
    if (!showAssign || !assignUserId) return
    setSaving(true); setActionError('')
    try {
      await assets.assign(showAssign.id, Number(assignUserId))
      setShowAssign(null); setAssignUserId('')
      reload()
    } catch (e: any) {
      setActionError(e?.response?.data?.message ?? 'Erro ao atribuir ativo')
    } finally { setSaving(false) }
  }

  const handleUnassign = async (asset: AssetResponse) => {
    if (!confirm(`Remover atribuição do ativo ${asset.assetTag}? O ativo voltará para Disponível.`)) return
    setActionError('')
    try {
      await assets.unassign(asset.id)
      reload()
    } catch (e: any) {
      setActionError(e?.response?.data?.message ?? 'Erro ao remover atribuição')
    }
  }

  const handleTransfer = async () => {
    if (!showTransfer || !transferForm.toUnitId || !transferForm.reason) return
    setSaving(true); setActionError('')
    try {
      await assets.transfer({
        assetId: showTransfer.id,
        toUnitId: Number(transferForm.toUnitId),
        reason: transferForm.reason,
      })
      setShowTransfer(null); setTransferForm({ toUnitId: '', reason: '' })
      reload()
    } catch (e: any) {
      setActionError(e?.response?.data?.message ?? 'Erro ao solicitar transferência')
    } finally { setSaving(false) }
  }

  const handleMaintenance = async () => {
    if (!showMaint || maintDesc.length < 10) return
    setSaving(true); setActionError('')
    try {
      const estimatedCost = maintCost ? parseCurrency(maintCost) : undefined
      await assets.maintenance({ assetId: showMaint.id, description: maintDesc, estimatedCost })
      setShowMaint(null); setMaintDesc(''); setMaintCost('')
      reload()
    } catch (e: any) {
      setActionError(e?.response?.data?.message ?? 'Erro ao abrir manutenção')
    } finally { setSaving(false) }
  }

  const handleRetire = async () => {
    if (!showRetire) return
    setSaving(true); setActionError('')
    try {
      await assets.retire(showRetire.id)
      setShowRetire(null)
      reload()
    } catch (e: any) {
      setActionError(e?.response?.data?.message ?? 'Erro ao aposentar ativo')
    } finally { setSaving(false) }
  }

  // No modo insurance, filtra client-side para só mostrar ativos com seguro a vencer
  const pageContent = assets.page?.content ?? []
  const visibleContent = insuranceMode && expiringAssetIds.size > 0
    ? pageContent.filter((a) => expiringAssetIds.has(a.id))
    : pageContent

  const page = assets.page
  const totalPages = page?.totalPages ?? 0

  // Colunas da tabela — adiciona "Seguro" no modo insurance
  const baseHeaders = [
    'Código do Ativo', 'Modelo', 'Tipo',
    ...(effectiveUnitId ? [] : ['Unidade']),
    ...(effectiveAssignedUserId ? [] : ['Responsável']),
    'Status',
    ...(insuranceMode ? ['Seguro'] : []),
    'Ações',
  ]
  const colSpan = baseHeaders.length

  return (
    <div>
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">Ativos</h1>
          <p className="text-[13px] text-slate-500 mt-1">
            {insuranceMode
              ? 'Ativos com apólice de seguro a vencer em até 30 dias'
              : effectiveAssignedUserId
              ? 'Ativos atribuídos a você'
              : effectiveUnitId
              ? 'Ativos da sua unidade'
              : 'Ciclo de vida completo dos ativos da organização'}
          </p>
        </div>
        <div className="flex gap-2">
          <button data-testid="asset-export-btn" onClick={() => exportApi.downloadAssets(undefined, undefined)} className="flex items-center gap-[7px] px-4 py-2 rounded-[8px] border-[1.5px] border-slate-200 bg-white text-[13px] font-semibold hover:bg-slate-50 transition">
            <Download size={14} /> Exportar CSV
          </button>
          {(isAdmin || isGestor) && (
            <button data-testid="asset-new-btn" onClick={() => setShowCreate(true)} className="flex items-center gap-[7px] px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition">
              <Plus size={14} /> Novo Ativo
            </button>
          )}
        </div>
      </div>

      <ErrorBanner message={actionError || assets.error} onDismiss={() => setActionError('')} />

      {/* Banner informativo no modo insurance */}
      {insuranceMode && (
        <div className="flex items-center gap-2 mb-4 px-4 py-3 rounded-[8px] bg-red-50 border border-red-200 text-red-800 text-[13px]">
          <ShieldAlert size={15} className="flex-shrink-0" />
          <span>Exibindo apenas ativos com apólice de seguro a vencer em até 30 dias. Acesse o detalhe do ativo para renovar.</span>
        </div>
      )}

      <div className="bg-white rounded-[10px] border border-slate-200 overflow-hidden shadow-sm">
        {/* Barra de busca — oculta no modo insurance pois o filtro já é fixo */}
        {!insuranceMode && (
          <div className="flex items-center gap-2 px-4 py-[14px] border-b border-slate-100">
            <div className="relative flex-1 max-w-[320px]">
              <Search size={14} className="absolute left-[10px] top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                data-testid="asset-search-input"
                value={search}
                onChange={(e) => { setSearch(e.target.value); setCurrentPage(0) }}
                placeholder="Buscar por modelo ou código..."
                className="w-full border-[1.5px] border-slate-200 rounded-[7px] py-2 pl-8 pr-3 text-[13px] bg-slate-50 outline-none focus:border-blue-600 focus:bg-white transition"
              />
            </div>
          </div>
        )}

        {/* Filtros de status — ocultos no modo insurance */}
        {!insuranceMode && (
          <div className="flex gap-[6px] px-4 py-[10px] border-b border-slate-100 flex-wrap items-center">
            {STATUS_FILTERS.map((f) => (
              <button
                key={f.value}
                data-testid={`asset-status-filter-${String(f.value).toLowerCase()}`}
                onClick={() => { setStatusFilter(f.value); setCurrentPage(0) }}
                className={`px-3 py-1 rounded-full text-[12px] font-medium border-[1.5px] transition ${
                  statusFilter === f.value
                    ? 'bg-blue-100 text-blue-700 border-blue-500'
                    : 'bg-white text-slate-500 border-slate-200 hover:border-blue-400'
                }`}
              >
                {f.label}{f.value === 'ALL' && page ? ` (${page.totalElements})` : ''}
              </button>
            ))}
            <div className="ml-2 pl-2 border-l border-slate-200">
              <select
                data-testid="asset-type-filter"
                value={typeFilter}
                onChange={(e) => { setTypeFilter(e.target.value as AssetType | 'ALL'); setCurrentPage(0) }}
                className="border-[1.5px] border-slate-200 rounded-[7px] px-3 py-[5px] text-[12px] bg-white outline-none text-slate-600 hover:border-blue-400 transition"
              >
                <option value="ALL">Todos os tipos</option>
                {ASSET_TYPE_OPTIONS.map((t) => (
                  <option key={t.value} value={t.value}>{t.label}</option>
                ))}
              </select>
            </div>
          </div>
        )}

        <div className="overflow-x-auto">
          <table data-testid="assets-table" className="w-full border-collapse">
            <thead className="bg-slate-50">
              <tr>
                {baseHeaders.map((h) => (
                  <th key={h} className="px-[14px] py-[10px] text-left text-[11px] font-bold text-slate-400 uppercase tracking-[.5px] border-b border-slate-200">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {assets.loading ? (
                <tr><td colSpan={colSpan} className="text-center py-12 text-slate-400">Carregando...</td></tr>
              ) : visibleContent.length === 0 ? (
                <tr><td colSpan={colSpan} className="text-center py-12 text-slate-400">Nenhum ativo encontrado</td></tr>
              ) : visibleContent.map((asset) => {
                const ins = expiringMap.get(asset.id)
                const days = ins ? daysUntil(ins.expiryDate) : null
                return (
                  <tr key={asset.id} data-testid="asset-row" className="hover:bg-slate-50 transition-colors">
                    <td className="px-[14px] py-3 border-b border-slate-50">
                      <span className="font-mono text-[12px] text-blue-700 font-medium">{asset.assetTag}</span>
                    </td>
                    <td className="px-[14px] py-3 border-b border-slate-50 text-[13.5px]">{asset.model}</td>
                    <td className="px-[14px] py-3 border-b border-slate-50">
                      <span className="text-[11.5px] font-semibold bg-slate-100 text-slate-600 px-2 py-[3px] rounded-full">
                        {ASSET_TYPE_LABELS[asset.type] ?? asset.type}
                      </span>
                    </td>
                    {!effectiveUnitId && (
                      <td className="px-[14px] py-3 border-b border-slate-50 text-[13.5px] text-slate-600">
                        {resolveUnitName(asset.unitId, units)}
                      </td>
                    )}
                    {!effectiveAssignedUserId && (
                      <td className="px-[14px] py-3 border-b border-slate-50 text-[13.5px] text-slate-600">
                        {resolveUserName(asset.assignedUserId, users)}
                      </td>
                    )}
                    <td className="px-[14px] py-3 border-b border-slate-50">
                      <span className={`text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full ${ASSET_STATUS_COLORS[asset.status] ?? 'bg-slate-100 text-slate-500'}`}>
                        {ASSET_STATUS_LABELS[asset.status] ?? asset.status}
                      </span>
                    </td>

                    {/* Coluna seguro — só no modo insurance */}
                    {insuranceMode && (
                      <td className="px-[14px] py-3 border-b border-slate-50">
                        {ins ? (
                          <div>
                            <div className="text-[12px] font-semibold text-red-700">
                              {days !== null && days <= 0 ? 'Vencida' : `Vence em ${days} dia${days === 1 ? '' : 's'}`}
                            </div>
                            <div className="text-[11px] text-slate-400 mt-[1px]">
                              {ins.insurer} · {ins.policyNumber}
                            </div>
                            <div className="text-[11px] text-slate-400">
                              {new Date(ins.expiryDate).toLocaleDateString('pt-BR')}
                            </div>
                          </div>
                        ) : (
                          <span className="text-[11.5px] text-slate-300">—</span>
                        )}
                      </td>
                    )}

                    <td className="px-[14px] py-3 border-b border-slate-50">
                      <div className="flex gap-[5px]">
                        <TipButton testId="asset-action-view" tip="Ver detalhes" onClick={() => navigate(`/assets/${asset.id}`)}>
                          <Eye size={13} />
                        </TipButton>
                        {asset.status === 'AVAILABLE' && (
                          <TipButton testId="asset-action-assign" tip="Atribuir usuário" onClick={() => { setShowAssign(asset); setAssignUserId('') }}>
                            <UserCheck size={13} />
                          </TipButton>
                        )}
                        {asset.status === 'ASSIGNED' && (
                          <TipButton testId="asset-action-unassign" tip="Remover atribuição" onClick={() => handleUnassign(asset)}>
                            <UserX size={13} />
                          </TipButton>
                        )}
                        {asset.status === 'AVAILABLE' && (
                          <TipButton testId="asset-action-transfer" tip="Solicitar transferência" onClick={() => { setShowTransfer(asset); setTransferForm({ toUnitId: '', reason: '' }) }}>
                            <ArrowLeftRight size={13} />
                          </TipButton>
                        )}
                        {['AVAILABLE', 'ASSIGNED'].includes(asset.status) && (
                          <TipButton testId="asset-action-maintenance" tip="Abrir manutenção" onClick={() => { setShowMaint(asset); setMaintDesc('') }}>
                            <Wrench size={13} />
                          </TipButton>
                        )}
                        {(isAdmin || isGestor) && asset.status !== 'RETIRED' && (
                          <TipButton testId="asset-action-retire" tip="Aposentar ativo" danger onClick={() => setShowRetire(asset)}>
                            <Trash2 size={13} />
                          </TipButton>
                        )}
                      </div>
                    </td>
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>

        {page && !insuranceMode && (
          <Pagination
            currentPage={currentPage}
            totalPages={totalPages}
            totalElements={page.totalElements}
            pageSize={10}
            isFirst={page.first}
            isLast={page.last}
            onPageChange={setCurrentPage}
          />
        )}
      </div>

      <CreateAssetModal
        open={showCreate}
        onClose={() => setShowCreate(false)}
        form={createForm}
        setForm={setCreateForm}
        units={units}
        onConfirm={handleCreate}
        saving={saving}
        error={actionError}
      />
      <AssignUserModal
        asset={showAssign}
        onClose={() => setShowAssign(null)}
        users={users}
        assignUserId={assignUserId}
        setAssignUserId={setAssignUserId}
        onConfirm={handleAssign}
        saving={saving}
      />
      <TransferModal
        asset={showTransfer}
        onClose={() => setShowTransfer(null)}
        units={units}
        form={transferForm}
        setForm={setTransferForm}
        onConfirm={handleTransfer}
        saving={saving}
      />
      <MaintenanceModal
        asset={showMaint}
        onClose={() => { setShowMaint(null); setMaintCost('') }}
        desc={maintDesc}
        setDesc={setMaintDesc}
        cost={maintCost}
        setCost={setMaintCost}
        onConfirm={handleMaintenance}
        saving={saving}
      />
      <RetireModal
        asset={showRetire}
        onCancel={() => setShowRetire(null)}
        onConfirm={handleRetire}
        loading={saving}
      />
    </div>
  )
}

import { useState, useEffect } from 'react'
import { Plus, Trash2 } from 'lucide-react'
import { insuranceApi } from '../../../../api'
import type { AssetInsurance } from '../../../../types'
import {
  Field,
  ModalFooter,
  Pagination,
  formatCurrency,
  formatCurrencyInput,
  formatDate,
  parseCurrency,
} from '../../../../shared'

const INPUT_CLS =
  'w-full border-[1.5px] border-slate-200 rounded-[7px] px-3 py-[9px] text-[13.5px] outline-none bg-slate-50 focus:border-blue-600 focus:bg-white transition'

const INS_PAGE_SIZE = 5

function insuranceStatus(ins: AssetInsurance) {
  return new Date(ins.expiryDate) < new Date()
    ? { label: 'Vencido', cls: 'bg-red-100 text-red-700' }
    : { label: 'Ativo', cls: 'bg-emerald-100 text-emerald-700' }
}

interface TabInsuranceProps {
  assetId: number
  insurance: AssetInsurance[]
  setInsurance: React.Dispatch<React.SetStateAction<AssetInsurance[]>>
  isAdmin: boolean
  isGestor: boolean
  retired?: boolean
}

export function TabInsurance({
  assetId,
  insurance,
  setInsurance,
  isAdmin,
  isGestor,
  retired = false,
}: TabInsuranceProps) {
  const [insPage, setInsPage] = useState(0)
  const [showIns, setShowIns] = useState(false)
  const [insForm, setInsForm] = useState({
    policyNumber: '',
    insurer: '',
    coverageValue: '',
    premium: '',
    startDate: '',
    expiryDate: '',
  })
  const [saving, setSaving] = useState(false)
  const [insError, setInsError] = useState('')

  const insTotalPages = Math.ceil(insurance.length / INS_PAGE_SIZE)

  // ✅ garante que página nunca fica inválida
  useEffect(() => {
    if (insPage > 0 && insPage >= insTotalPages) {
      setInsPage(insTotalPages - 1)
    }
  }, [insurance.length, insTotalPages, insPage])

  const insSlice = insurance.slice(
    insPage * INS_PAGE_SIZE,
    (insPage + 1) * INS_PAGE_SIZE
  )

  const handleAdd = async () => {
    setInsError('')

    if (
      !insForm.policyNumber ||
      !insForm.insurer ||
      !insForm.coverageValue ||
      !insForm.startDate ||
      !insForm.expiryDate
    ) {
      setInsError('Preencha todos os campos obrigatórios')
      return
    }

    // ✅ comparação correta de datas
    if (new Date(insForm.expiryDate) <= new Date(insForm.startDate)) {
      setInsError('A data de vencimento deve ser posterior à data de início')
      return
    }

    if (parseCurrency(insForm.coverageValue) <= 0) {
      setInsError('O valor de cobertura deve ser maior que zero')
      return
    }

    setSaving(true)
    try {
      const created = await insuranceApi.create(assetId, {
        policyNumber: insForm.policyNumber,
        insurer: insForm.insurer,
        coverageValue: parseCurrency(insForm.coverageValue),
        premium: insForm.premium
          ? parseCurrency(insForm.premium)
          : undefined,
        startDate: insForm.startDate,
        expiryDate: insForm.expiryDate,
      })

      setInsurance((prev) => [created, ...prev])

      setInsForm({
        policyNumber: '',
        insurer: '',
        coverageValue: '',
        premium: '',
        startDate: '',
        expiryDate: '',
      })

      setShowIns(false)
    } catch (e: any) {
      setInsError(
        e?.response?.data?.error?.message ??
          e?.response?.data?.message ??
          'Erro ao cadastrar apólice'
      )
    } finally {
      setSaving(false)
    }
  }

  const handleDelete = async (insId: number) => {
    if (!confirm('Tem certeza que deseja remover esta apólice?')) return
    try {
      await insuranceApi.delete(insId)
      setInsurance((prev) => prev.filter((i) => i.id !== insId))
    } catch (e) {
      console.error(e)
    }
  }

  return (
    <div>
      {(isAdmin || isGestor) && !retired && (
        <div className="flex justify-end mb-3">
          <button
            type="button"
            onClick={() => setShowIns(true)}
            className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition"
          >
            <Plus size={14} /> Cadastrar Apólice
          </button>
        </div>
      )}

      {insurance.length === 0 ? (
        <div className="bg-white rounded-[10px] border border-slate-200 p-10 text-center text-slate-400 shadow-sm">
          Nenhuma apólice cadastrada
        </div>
      ) : (
        <>
          {insSlice.map((ins) => {
            const st = insuranceStatus(ins)
            return (
              <div
                key={ins.id}
                className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm mb-3"
              >
                <div className="flex justify-between items-start mb-3">
                  <div className="flex items-center gap-2">
                    <span className="font-mono text-[13px] font-bold text-blue-700">
                      {ins.policyNumber}
                    </span>
                    <span
                      className={`text-[11px] font-semibold px-[8px] py-[2px] rounded-full ${st.cls}`}
                    >
                      {st.label}
                    </span>
                  </div>

                  {(isAdmin || isGestor) && !retired && (
                    <button
                      type="button"
                      onClick={() => handleDelete(ins.id)}
                      className="w-[28px] h-[28px] rounded-[6px] border border-red-200 text-red-500 hover:bg-red-50 flex items-center justify-center transition"
                    >
                      <Trash2 size={13} />
                    </button>
                  )}
                </div>

                <div className="grid grid-cols-3 gap-4">
                  {[
                    { label: 'Seguradora', val: ins.insurer },
                    { label: 'Cobertura', val: formatCurrency(ins.coverageValue) },
                    { label: 'Prêmio', val: ins.premium ? formatCurrency(ins.premium) : 'N/A' },
                    { label: 'Início', val: formatDate(ins.startDate) },
                    { label: 'Vencimento', val: formatDate(ins.expiryDate) },
                  ].map((f) => (
                    <div key={f.label}>
                      <div className="text-[10.5px] text-slate-400 uppercase tracking-[.4px] mb-1">
                        {f.label}
                      </div>
                      <div className="text-[13.5px] font-semibold">{f.val}</div>
                    </div>
                  ))}
                </div>
              </div>
            )
          })}

          <Pagination
            currentPage={insPage}
            totalPages={insTotalPages}
            totalElements={insurance.length}
            pageSize={INS_PAGE_SIZE}
            isFirst={insPage === 0}
            isLast={insPage >= insTotalPages - 1}
            onPageChange={setInsPage}
            currentCount={insSlice.length}
          />
        </>
      )}

      {showIns && (
        <div
          className="fixed inset-0 bg-slate-900/50 z-50 flex items-center justify-center p-5"
          onClick={(e) =>
            e.target === e.currentTarget && setShowIns(false)
          }
        >
          <div className="bg-white rounded-[14px] w-full max-w-[520px] shadow-2xl max-h-[90vh] overflow-y-auto">
            <div className="flex justify-between items-center px-6 pt-5 pb-0">
              <h2 className="text-[17px] font-bold">
                Cadastrar Apólice de Seguro
              </h2>
              <button
                type="button"
                onClick={() => setShowIns(false)}
                className="w-7 h-7 rounded-[6px] border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-slate-50"
              >
                ✕
              </button>
            </div>

            <div className="px-6 py-5">
              <div className="grid grid-cols-2 gap-3">
                <Field label="Número da Apólice *">
                  <input
                    value={insForm.policyNumber}
                    maxLength={50}
                    onChange={(e) =>
                      setInsForm((f) => ({
                        ...f,
                        policyNumber: e.target.value,
                      }))
                    }
                    className={INPUT_CLS}
                  />
                </Field>

                <Field label="Seguradora *">
                  <input
                    value={insForm.insurer}
                    maxLength={100}
                    onChange={(e) =>
                      setInsForm((f) => ({
                        ...f,
                        insurer: e.target.value,
                      }))
                    }
                    className={INPUT_CLS}
                  />
                </Field>

                <Field label="Valor de Cobertura *">
                  <input
                    inputMode="numeric"
                    value={insForm.coverageValue}
                    maxLength={15}
                    onChange={(e) =>
                      setInsForm((f) => ({
                        ...f,
                        coverageValue: formatCurrencyInput(e.target.value),
                      }))
                    }
                    className={INPUT_CLS}
                  />
                </Field>

                <Field label="Prêmio">
                  <input
                    inputMode="numeric"
                    value={insForm.premium}
                    maxLength={15}
                    onChange={(e) =>
                      setInsForm((f) => ({
                        ...f,
                        premium: formatCurrencyInput(e.target.value),
                      }))
                    }
                    className={INPUT_CLS}
                  />
                </Field>

                <Field label="Início *">
                  <input
                    type="date"
                    value={insForm.startDate}
                    onChange={(e) =>
                      setInsForm((f) => ({
                        ...f,
                        startDate: e.target.value,
                      }))
                    }
                    className={INPUT_CLS}
                  />
                </Field>

                <Field label="Vencimento *">
                  <input
                    type="date"
                    value={insForm.expiryDate}
                    onChange={(e) =>
                      setInsForm((f) => ({
                        ...f,
                        expiryDate: e.target.value,
                      }))
                    }
                    className={INPUT_CLS}
                  />
                </Field>
              </div>

              {insError && (
                <div className="bg-red-50 border border-red-200 rounded-[8px] p-3 text-[12.5px] text-red-700 mt-2">
                  {insError}
                </div>
              )}

              <ModalFooter
                onCancel={() => {
                  setShowIns(false)
                  setInsError('')
                }}
                onConfirm={handleAdd}
                loading={saving}
                confirmLabel="Cadastrar"
              />
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useEffect, useState, useCallback } from 'react'
import { Download, Package, ArrowLeftRight, Wrench, Users, Shield, Filter, X } from 'lucide-react'
import { auditApi, exportApi, userApi, unitApi, organizationApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { AuditEvent, UserResponse, UnitResponse } from '../../types'
import {
  AUDIT_EVENT_LABELS, AUDIT_EVENT_FILTER_OPTIONS,
  resolveUserName, resolveUnitName,
  DateRangeFilter, ErrorBanner,
} from '../../shared'

const EVENT_ICON: Record<string, React.ReactNode> = {
  ASSET: <Package size={14} />, TRANSFER: <ArrowLeftRight size={14} />,
  MAINTENANCE: <Wrench size={14} />, USER: <Users size={14} />, DEFAULT: <Shield size={14} />,
}
const EVENT_COLOR: Record<string, string> = {
  ASSET: 'bg-blue-100 text-blue-700', TRANSFER: 'bg-purple-100 text-purple-700',
  MAINTENANCE: 'bg-amber-100 text-amber-700', USER: 'bg-red-100 text-red-700',
  DEFAULT: 'bg-slate-100 text-slate-500',
}

const AUDIT_DETAILS: Record<string, string> = {
  'User created': 'Usuário criado',
  'User activated': 'Usuário ativado',
  'User blocked': 'Usuário bloqueado',
  'User inactivated': 'Usuário inativado',
  'Unit created': 'Unidade criada',
  'Unit activated': 'Unidade ativada',
  'Unit inactivated': 'Unidade inativada',
  'Asset created': 'Ativo criado',
  'Asset updated': 'Ativo atualizado',
  'Asset retired': 'Ativo aposentado',
  'Asset assigned': 'Ativo atribuído',
  'Asset unassigned': 'Ativo desatribuído',
  'Transfer requested': 'Transferência solicitada',
  'Transfer approved': 'Transferência aprovada',
  'Transfer rejected': 'Transferência rejeitada',
  'Transfer completed': 'Transferência concluída',
  'Transfer cancelled': 'Transferência cancelada',
  'Maintenance opened': 'Manutenção aberta',
  'Maintenance started': 'Manutenção iniciada',
  'Maintenance completed': 'Manutenção concluída',
  'Maintenance cancelled': 'Manutenção cancelada',
}

const PAGE_SIZE = 20

function getGroup(type: string): string {
  const keys = Object.keys(EVENT_ICON).filter((k) => k !== 'DEFAULT')
  return keys.find((k) => type.startsWith(k)) ?? 'DEFAULT'
}

function translateDetails(details?: string) {
  if (!details) return undefined
  return AUDIT_DETAILS[details] ?? details
}

export default function AuditPage() {
  const { user } = useAuth()
  const [events, setEvents] = useState<AuditEvent[]>([])
  const [users, setUsers] = useState<UserResponse[]>([])
  const [units, setUnits] = useState<UnitResponse[]>([])
  const [orgName, setOrgName] = useState('')
  const [loading, setLoading] = useState(true)
  const [typeFilter, setTypeFilter] = useState('')
  const [startDate, setStartDate] = useState('')
  const [endDate, setEndDate] = useState('')
  const [currentPage, setCurrentPage] = useState(0)
  const [total, setTotal] = useState(0)
  const [filterError, setFilterError] = useState('')

  useEffect(() => {
    if (!user) return
    userApi.list({ size: 200 })
      .then((p) => setUsers(Array.isArray(p?.content) ? p.content : []))
      .catch(console.error)

    if (user.organizationId) {
      unitApi.listByOrg(user.organizationId)
        .then((l) => setUnits(Array.isArray(l) ? l : []))
        .catch(console.error)

      organizationApi.getById(user.organizationId)
        .then((o) => setOrgName(o.name))
        .catch(console.error)
    }
  }, [user])

  const load = useCallback(() => {
    if (startDate && endDate && endDate < startDate) {
      setFilterError('A data final deve ser posterior à data inicial')
      return
    }

    setFilterError('')
    setLoading(true)

    let fn: Promise<AuditEvent[] | { content: AuditEvent[] }>

    if (startDate && endDate && user?.organizationId) {
      fn = auditApi.byPeriod(user.organizationId, startDate, endDate)
    } else if (typeFilter) {
      fn = auditApi.byType(typeFilter)
    } else {
      fn = auditApi.list({ sort: 'createdAt,desc' })
    }

    fn.then((items) => {
      const result = items as { content?: AuditEvent[] }

      const all = Array.isArray(items)
        ? items
        : Array.isArray(result.content)
          ? result.content
          : []

      const filtered = typeFilter && (startDate || endDate)
        ? all.filter((e: AuditEvent) => e.eventType === typeFilter)
        : all

      setTotal(filtered.length)
      setEvents(filtered.slice(currentPage * PAGE_SIZE, (currentPage + 1) * PAGE_SIZE))
    })
      .catch((e) => {
        console.error(e)
        setEvents([])
        setTotal(0)
      })
      .finally(() => setLoading(false))
  }, [typeFilter, currentPage, startDate, endDate, user?.organizationId])

  useEffect(() => { load() }, [load])

  const clearFilters = () => {
    setTypeFilter('')
    setStartDate('')
    setEndDate('')
    setCurrentPage(0)
    setFilterError('')
  }

  const hasActiveFilters = typeFilter || startDate || endDate
  const totalPages = Math.ceil(total / PAGE_SIZE)

  return (
    <div>
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">Auditoria</h1>
          <p className="text-[13px] text-slate-500 mt-1">Rastreamento completo de eventos da organização</p>
        </div>
        <button
          onClick={() => exportApi.downloadAudit(startDate || undefined, endDate || undefined)}
          className="flex items-center gap-2 px-4 py-2 rounded-[8px] border-[1.5px] border-slate-200 bg-white text-[13px] font-semibold hover:bg-slate-50 transition">
          <Download size={14} /> Exportar CSV
        </button>
      </div>

      <div className="bg-white rounded-[10px] border border-slate-200 p-4 mb-4 shadow-sm">
        <div className="flex gap-3 flex-wrap items-end">
          <div>
            <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-[.4px] mb-[5px]">Tipo de evento</label>
            <select
              value={typeFilter}
              onChange={(e) => { setTypeFilter(e.target.value); setCurrentPage(0) }}
              className="border-[1.5px] border-slate-200 rounded-[7px] px-3 py-[7px] text-[13px] bg-slate-50 outline-none min-w-[200px]">
              <option value="">Todos os tipos</option>
              {AUDIT_EVENT_FILTER_OPTIONS.map(({ value, label }) => (
                <option key={value} value={value}>{label}</option>
              ))}
            </select>
          </div>

          <DateRangeFilter
            startDate={startDate}
            endDate={endDate}
            onStartChange={(v) => { setStartDate(v); setCurrentPage(0); setFilterError('') }}
            onEndChange={(v) => { setEndDate(v); setCurrentPage(0); setFilterError('') }}
            onClear={clearFilters}
            error={filterError}
          />

          <div className="flex gap-2 items-center">
            <button
              onClick={load}
              className="flex items-center gap-2 px-4 py-[7px] rounded-[7px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition">
              <Filter size={13} /> Filtrar
            </button>

            {hasActiveFilters && (
              <button
                onClick={clearFilters}
                className="flex items-center gap-1 px-3 py-[7px] rounded-[7px] border border-slate-200 text-[13px] text-slate-500 hover:bg-slate-50 transition">
                <X size={12} /> Limpar
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[10px] border border-slate-200 overflow-hidden shadow-sm">
        {loading ? (
          <div className="text-center py-12 text-slate-400">Carregando...</div>
        ) : events.length === 0 ? (
          <div className="text-center py-12 text-slate-400">Nenhum evento encontrado</div>
        ) : (
          events.map((e) => {
            const group = getGroup(e.eventType)
            return (
              <div key={e.id} className="flex items-start gap-[14px] px-[18px] py-[13px] border-b border-slate-50 last:border-0 hover:bg-slate-50 transition">
                <div className={`w-[34px] h-[34px] rounded-full flex items-center justify-center flex-shrink-0 mt-[1px] ${EVENT_COLOR[group]}`}>
                  {EVENT_ICON[group]}
                </div>

                <div className="flex-1">
                  <div className="text-[13px] font-bold text-slate-800">
                    {AUDIT_EVENT_LABELS[e.eventType] ?? e.eventType}
                  </div>

                  <div className="text-[12.5px] text-slate-500 mt-[2px]">
                    Responsável: <strong>{resolveUserName(e.actorUserId, users)}</strong>
                    {e.details && <>{' · '}{translateDetails(e.details)}</>}
                  </div>

                  <div className="flex gap-3 mt-[5px] text-[11px] text-slate-400 flex-wrap">
                    <span>Organização: {orgName || 'Carregando...'}</span>
                    <span>Unidade: {resolveUnitName(e.unitId, units)}</span>
                  </div>
                </div>

                <div className="text-[11.5px] text-slate-400 whitespace-nowrap mt-[2px]">
                  {new Date(e.createdAt).toLocaleString('pt-BR')}
                </div>
              </div>
            )
          })
        )}

        <div className="flex items-center justify-between px-4 py-[11px] border-t border-slate-100">
          <span className="text-[13px] text-slate-500">
            {total > 0
              ? <>Exibindo <strong>{currentPage * PAGE_SIZE + 1}–{Math.min((currentPage + 1) * PAGE_SIZE, total)}</strong> de <strong>{total}</strong></>
              : 'Nenhum resultado'
            }
          </span>

          {totalPages > 1 && (
            <div className="flex gap-1">
              {[...Array(Math.min(5, totalPages))].map((_, i) => {
                const half = 2
                let start = Math.max(0, currentPage - half)
                const end = Math.min(totalPages - 1, start + 4)
                if (end - start < 4) start = Math.max(0, end - 4)
                const page = start + i
                if (page > totalPages - 1) return null
                return (
                  <button
                    key={page}
                    onClick={() => setCurrentPage(page)}
                    disabled={page === currentPage}
                    className={`w-7 h-7 rounded-[6px] border-[1.5px] text-[12px] font-semibold flex items-center justify-center transition ${
                      page === currentPage
                        ? 'bg-blue-700 text-white border-blue-700'
                        : 'bg-white text-slate-500 border-slate-200 hover:border-blue-400 disabled:opacity-40'
                    }`}>
                    {page + 1}
                  </button>
                )
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Package, Wrench, ArrowLeftRight, TrendingUp, UserCheck } from 'lucide-react'
import { dashboardApi, maintenanceApi, transferApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { UnitDashboard, MaintenanceResponse } from '../../types'
import {
  MAINTENANCE_STATUS_LABELS, MAINTENANCE_STATUS_COLORS,
  formatCurrency, formatCode, formatDate,
} from '../../shared'

interface MetricCardProps {
  label: string; value: string | number; sub?: string
  accent: string; icon: React.ReactNode; alert?: boolean; onClick?: () => void
}
function MetricCard({ label, value, sub, accent, icon, alert, onClick }: MetricCardProps) {
  const accentMap: Record<string, { bg: string; text: string; bar: string }> = {
    blue:   { bg: 'bg-blue-100',    text: 'text-blue-700',    bar: 'bg-blue-500' },
    red:    { bg: 'bg-red-100',     text: 'text-red-700',     bar: 'bg-red-500' },
    amber:  { bg: 'bg-amber-100',   text: 'text-amber-700',   bar: 'bg-amber-500' },
    green:  { bg: 'bg-emerald-100', text: 'text-emerald-700', bar: 'bg-emerald-500' },
    purple: { bg: 'bg-violet-100',  text: 'text-violet-700',  bar: 'bg-violet-500' },
    slate:  { bg: 'bg-slate-100',   text: 'text-slate-600',   bar: 'bg-slate-400' },
  }
  const c = accentMap[accent] ?? accentMap.slate
  return (
    <div onClick={onClick}
      className={`relative bg-white rounded-[12px] border shadow-sm overflow-hidden flex gap-4 items-center p-5 transition-all ${
        alert ? 'border-red-300 ring-1 ring-red-200' : 'border-slate-200'
      } ${onClick ? 'cursor-pointer hover:shadow-md' : ''}`}
    >
      <div className={`w-[46px] h-[46px] rounded-[10px] flex-shrink-0 flex items-center justify-center ${c.bg} ${c.text}`}>{icon}</div>
      <div className="flex-1 min-w-0">
        <div className="text-[26px] font-bold tracking-tight leading-none">{value}</div>
        <div className="text-[13px] text-slate-600 mt-[5px] font-medium">{label}</div>
        {sub && <div className="text-[11.5px] text-slate-400 mt-[2px]">{sub}</div>}
      </div>
      <div className={`absolute bottom-0 left-0 right-0 h-[3px] ${c.bar}`} />
    </div>
  )
}

export function GestorDashboard() {
  const navigate = useNavigate()
  const { user } = useAuth()
  const [data, setData] = useState<UnitDashboard | null>(null)
  const [openMaintenances, setOpenMaintenances] = useState<MaintenanceResponse[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!user) return
    const unitId = user.unitId
    Promise.all([
      dashboardApi.unit(),
      maintenanceApi.list({
        size: 5,
        sort: 'createdAt,desc',
        ...(unitId ? { unitId } : {}),
        status: 'IN_PROGRESS',
      }),
    ])
      .then(([dash, maint]) => {
        setData(dash)
        setOpenMaintenances(Array.isArray(maint?.content) ? maint.content : [])
      })
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [user])

  if (!user || loading) return <div className="flex items-center justify-center h-64 text-slate-400">Carregando...</div>
  if (!data) return <div className="flex items-center justify-center h-64 text-slate-400">Nenhum dado disponível</div>

  const unitId = user.unitId
  const assigned = data.assetsByStatus?.ASSIGNED ?? 0
  const retired  = data.assetsByStatus?.RETIRED ?? 0
  const activeTotal = (data.totalAssets ?? 0) - retired
  const utilizationRate = data.utilizationRate ?? (activeTotal > 0 ? Math.round((assigned / activeTotal) * 100) : 0)
  const available = data.assetsAvailable ?? (data.assetsByStatus?.AVAILABLE ?? 0)

  return (
    <div className="space-y-5">
      <div>
        <h1 className="text-[20px] font-bold tracking-tight">Painel da Unidade</h1>
        <p className="text-[13px] text-slate-500 mt-1">Indicadores operacionais da sua unidade</p>
      </div>

      <div className="grid grid-cols-3 gap-[14px]">
        {/* Ativos na unidade → lista todos os ativos da unidade */}
        <MetricCard
          label="Ativos na unidade"
          value={activeTotal.toLocaleString('pt-BR')}
          sub={`${available} disponível${available !== 1 ? 'is' : ''} para atribuição`}
          accent="blue" icon={<Package size={20} />}
          onClick={() => unitId ? navigate(`/assets?unitId=${unitId}`) : navigate('/assets')}
        />
        {/* Taxa de utilização → métrica calculada, não navegável */}
        <MetricCard
          label="Taxa de utilização"
          value={`${utilizationRate}%`}
          sub={`${assigned} atribuído${assigned !== 1 ? 's' : ''} de ${activeTotal} ativos`}
          accent={utilizationRate < 60 ? 'amber' : 'green'} icon={<TrendingUp size={20} />}
        />
        {/* Em manutenção → ordens abertas (REQUESTED + IN_PROGRESS) da unidade */}
        <MetricCard
          label="Em manutenção agora"
          value={data.totalMaintenance ?? 0}
          sub={`Custo real no mês: ${formatCurrency(data.maintenanceCostMonth ?? 0)}`}
          accent={(data.totalMaintenance ?? 0) > 5 ? 'red' : 'amber'}
          alert={(data.totalMaintenance ?? 0) > 5}
          icon={<Wrench size={20} />}
          onClick={() => unitId
            ? navigate(`/maintenance?unitId=${unitId}&status=OPEN`)
            : navigate('/maintenance?status=OPEN')
          }
        />
      </div>

      <div className="grid grid-cols-3 gap-[14px]">
        {/* Usuários na unidade → lista de usuários */}
        <MetricCard
          label="Usuários na unidade"
          value={data.totalUsers ?? 0}
          sub={`${Math.round((assigned / Math.max(data.totalUsers ?? 1, 1)) * 100)}% com ativo atribuído`}
          accent="purple" icon={<UserCheck size={20} />}
          onClick={() => navigate('/users')}
        />
        {/* Transferências pendentes → sempre navegável */}
        <MetricCard
          label="Transferências pendentes"
          value={data.pendingTransfersCount ?? 0}
          sub="de/para esta unidade"
          accent={(data.pendingTransfersCount ?? 0) > 0 ? 'amber' : 'slate'}
          icon={<ArrowLeftRight size={20} />}
          onClick={() => navigate('/transfers')}
        />
        {/* Ativos sem responsável → filtra AVAILABLE da unidade */}
        <MetricCard
          label="Ativos sem responsável"
          value={available}
          sub={available > 0 ? 'clique para atribuir' : 'todos os ativos têm responsável'}
          accent={available > 3 ? 'amber' : 'slate'}
          icon={<Package size={20} />}
          onClick={() => unitId
            ? navigate(`/assets?unitId=${unitId}&status=AVAILABLE`)
            : navigate('/assets?status=AVAILABLE')
          }
        />
      </div>

      <div className="grid grid-cols-2 gap-[14px]">
        {/* Manutenções em andamento */}
        <div className="bg-white rounded-[12px] border border-slate-200 p-[18px] shadow-sm">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-[14px] font-bold">Manutenções em andamento</h3>
            <button type="button"
              onClick={() => unitId
                ? navigate(`/maintenance?unitId=${unitId}&status=OPEN`)
                : navigate('/maintenance?status=OPEN')
              }
              className="text-[12px] text-blue-700 hover:underline font-medium">Ver todas →</button>
          </div>
          {openMaintenances.length === 0 ? (
            <div className="text-center py-8 text-slate-400 text-[13px]">Nenhuma manutenção em andamento</div>
          ) : (
            <ul className="space-y-px">
              {openMaintenances.map((m) => (
                <li key={m.id} className="flex items-center gap-3 py-[9px] border-b border-slate-50 last:border-0">
                  <span className={`text-[11px] font-semibold px-[8px] py-[2px] rounded-full flex-shrink-0 ${
                    MAINTENANCE_STATUS_COLORS[m.status as keyof typeof MAINTENANCE_STATUS_COLORS] ?? 'bg-slate-100 text-slate-500'
                  }`}>
                    {MAINTENANCE_STATUS_LABELS[m.status as keyof typeof MAINTENANCE_STATUS_LABELS] ?? m.status}
                  </span>
                  <div className="flex-1 min-w-0">
                    <div className="font-mono text-[11.5px] text-blue-700 font-bold">{formatCode('MNT', m.id)}</div>
                    <div className="text-[12px] text-slate-600 truncate" title={m.description}>{m.description}</div>
                  </div>
                  <div className="text-[11px] text-slate-400 flex-shrink-0">{formatDate(m.createdAt)}</div>
                </li>
              ))}
            </ul>
          )}
        </div>

        {/* Ativos disponíveis sem responsável */}
        <div className="bg-white rounded-[12px] border border-slate-200 p-[18px] shadow-sm">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-[14px] font-bold">Ativos sem responsável</h3>
            {(data.assetsIdleList ?? []).length > 0 && (
              <button type="button"
                onClick={() => unitId
                  ? navigate(`/assets?unitId=${unitId}&status=AVAILABLE`)
                  : navigate('/assets?status=AVAILABLE')
                }
                className="text-[12px] text-blue-700 hover:underline font-medium">Atribuir →</button>
            )}
          </div>
          {(data.assetsIdleList ?? []).length === 0 ? (
            <div className="text-center py-8 text-slate-400 text-[13px]">
              Todos os ativos têm responsável
            </div>
          ) : (
            <ul className="space-y-px">
              {(data.assetsIdleList ?? []).slice(0, 5).map((a) => (
                <li key={a.assetTag} className="flex items-center justify-between py-[9px] border-b border-slate-50 last:border-0">
                  <div>
                    <div className="font-mono text-[12px] text-blue-700 font-bold">{a.assetTag}</div>
                    <div className="text-[12px] text-slate-600">{a.model}</div>
                  </div>
                  <div className="text-right">
                    <span className="text-[11px] font-semibold px-[8px] py-[2px] rounded-full bg-slate-100 text-slate-600">
                      {a.idleDays}d sem uso
                    </span>
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Package, Wrench, ArrowLeftRight } from 'lucide-react'
import { dashboardApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { PersonalDashboard } from '../../types'
import {
  ASSET_STATUS_LABELS, ASSET_STATUS_COLORS,
  MAINTENANCE_STATUS_LABELS, MAINTENANCE_STATUS_COLORS,
  ASSET_TYPE_LABELS,
  formatCode, formatDate,
} from '../../shared'

interface MetricCardProps {
  label: string; value: string | number; sub?: string
  accent: string; icon: React.ReactNode; onClick?: () => void
}
function MetricCard({ label, value, sub, accent, icon, onClick }: MetricCardProps) {
  const accentMap: Record<string, { bg: string; text: string; bar: string }> = {
    blue:   { bg: 'bg-blue-100',    text: 'text-blue-700',    bar: 'bg-blue-500' },
    amber:  { bg: 'bg-amber-100',   text: 'text-amber-700',   bar: 'bg-amber-500' },
    purple: { bg: 'bg-violet-100',  text: 'text-violet-700',  bar: 'bg-violet-500' },
    slate:  { bg: 'bg-slate-100',   text: 'text-slate-600',   bar: 'bg-slate-400' },
    green:  { bg: 'bg-emerald-100', text: 'text-emerald-700', bar: 'bg-emerald-500' },
  }
  const c = accentMap[accent] ?? accentMap.slate
  return (
    <div onClick={onClick}
      className={`relative bg-white rounded-[12px] border border-slate-200 shadow-sm overflow-hidden flex gap-4 items-center p-5 transition-all ${onClick ? 'cursor-pointer hover:shadow-md' : ''}`}
    >
      <div className={`w-[46px] h-[46px] rounded-[10px] flex-shrink-0 flex items-center justify-center ${c.bg} ${c.text}`}>{icon}</div>
      <div className="flex-1 min-w-0">
        <div className="text-[26px] font-bold tracking-tight leading-none">{value}</div>
        <div className="text-[13px] text-slate-600 mt-[5px] font-medium">{label}</div>
        {sub && <div className="text-[11.5px] text-slate-400 mt-[2px]">{sub}</div>}
      </div>
      <div className={`absolute bottom-0 left-0 right-0 h-[3px] ${c.bar}`} />
    </div>
  )
}

export function OperadorDashboard() {
  const navigate = useNavigate()
  const { user } = useAuth()
  const [data, setData] = useState<PersonalDashboard | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!user) return
    dashboardApi.personal()
      .then(setData)
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [user])

  if (!user || loading) return <div className="flex items-center justify-center h-64 text-slate-400">Carregando...</div>
  if (!data) return <div className="flex items-center justify-center h-64 text-slate-400">Nenhum dado disponível</div>

  const userId = user.userId
  const myAssets = data.myAssets ?? []
  const myMaintenances = data.myOpenMaintenances ?? []
  const inMaintCount = myAssets.filter((a) => a.status === 'IN_MAINTENANCE').length

  // URL base para manutenções do operador — usa requestedByUserId que é o param correto da API
  const maintUrl = userId
    ? `/maintenance?requestedByUserId=${userId}&status=OPEN`
    : '/maintenance?status=OPEN'

  return (
    <div className="space-y-5">
      <div>
        <h1 className="text-[20px] font-bold tracking-tight">Meu Painel</h1>
        <p className="text-[13px] text-slate-500 mt-1">
          Olá{user.name ? `, ${user.name.split(' ')[0]}` : ''}. Aqui estão seus ativos e solicitações.
        </p>
      </div>

      <div className="grid grid-cols-3 gap-[14px]">
        {/* Meus ativos → filtra por assignedUserId */}
        <MetricCard
          label="Meus ativos"
          value={data.totalAssetsAssigned ?? 0}
          sub={inMaintCount > 0 ? `${inMaintCount} em manutenção` : 'todos em uso normal'}
          accent="blue" icon={<Package size={20} />}
          onClick={() => userId ? navigate(`/assets?assignedUserId=${userId}`) : navigate('/assets')}
        />
        {/* Manutenções abertas → filtra por requestedByUserId + status=OPEN */}
        <MetricCard
          label="Manutenções abertas"
          value={myMaintenances.length}
          sub={myMaintenances.length > 0 ? 'clique para acompanhar' : 'nenhuma ordem em aberto'}
          accent={myMaintenances.length > 0 ? 'amber' : 'slate'}
          icon={<Wrench size={20} />}
          onClick={() => navigate(maintUrl)}
        />
        {/* Transferências → sempre navegável */}
        <MetricCard
          label="Transferências em andamento"
          value={data.myPendingTransfers ?? 0}
          sub={(data.myPendingTransfers ?? 0) > 0 ? 'aguardando aprovação' : 'nenhuma em trânsito'}
          accent={(data.myPendingTransfers ?? 0) > 0 ? 'purple' : 'slate'}
          icon={<ArrowLeftRight size={20} />}
          onClick={() => navigate('/transfers')}
        />
      </div>

      <div className="grid grid-cols-2 gap-[14px]">
        {/* Lista dos meus ativos */}
        <div className="bg-white rounded-[12px] border border-slate-200 p-[18px] shadow-sm">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-[14px] font-bold">Meus ativos</h3>
            {myAssets.length > 0 && (
              <button type="button"
                onClick={() => userId ? navigate(`/assets?assignedUserId=${userId}`) : navigate('/assets')}
                className="text-[12px] text-blue-700 hover:underline font-medium">Ver todos →</button>
            )}
          </div>
          {myAssets.length === 0 ? (
            <div className="text-center py-8 text-slate-400 text-[13px]">
              <Package size={28} className="mx-auto mb-2 opacity-30" />
              Nenhum ativo atribuído a você
            </div>
          ) : (
            <ul className="space-y-px">
              {myAssets.map((a) => (
                <li key={a.assetTag} className="flex items-center gap-3 py-[10px] border-b border-slate-50 last:border-0">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="font-mono text-[12px] text-blue-700 font-bold">{a.assetTag}</span>
                      <span className="text-[11px] text-slate-400">
                        {ASSET_TYPE_LABELS[a.type as keyof typeof ASSET_TYPE_LABELS] ?? a.type}
                      </span>
                    </div>
                    <div className="text-[12.5px] text-slate-600 mt-[1px]">{a.model}</div>
                    {a.assignedSince && (
                      <div className="text-[11px] text-slate-400">desde {formatDate(a.assignedSince)}</div>
