                  </div>
                  <div className="flex flex-col items-end gap-1">
                    <span className={`text-[11px] font-semibold px-[8px] py-[2px] rounded-full ${ASSET_STATUS_COLORS[a.status as keyof typeof ASSET_STATUS_COLORS] ?? 'bg-slate-100 text-slate-500'}`}>
                      {ASSET_STATUS_LABELS[a.status as keyof typeof ASSET_STATUS_LABELS] ?? a.status}
                    </span>
                    {a.maintenanceCode && (
                      <span className="font-mono text-[10.5px] text-amber-600">{a.maintenanceCode}</span>
                    )}
                  </div>
                </li>
              ))}
            </ul>
          )}
        </div>

        {/* Manutenções abertas */}
        <div className="bg-white rounded-[12px] border border-slate-200 p-[18px] shadow-sm">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-[14px] font-bold">Minhas manutenções</h3>
            {myMaintenances.length > 0 && (
              <button type="button"
                onClick={() => navigate(maintUrl)}
                className="text-[12px] text-blue-700 hover:underline font-medium">Ver todas →</button>
            )}
          </div>
          {myMaintenances.length === 0 ? (
            <div className="text-center py-8 text-slate-400 text-[13px]">
              <Wrench size={28} className="mx-auto mb-2 opacity-30" />
              Nenhuma manutenção em aberto
            </div>
          ) : (
            <ul className="space-y-px">
              {myMaintenances.map((m) => (
                <li key={m.code} className="flex items-center gap-3 py-[10px] border-b border-slate-50 last:border-0">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                      <span className="font-mono text-[12px] text-blue-700 font-bold">{m.code}</span>
                      <span className="font-mono text-[11px] text-slate-400">{m.assetTag}</span>
                    </div>
                    <div className="text-[11px] text-slate-400 mt-[1px]">Aberta em {formatDate(m.createdAt)}</div>
                  </div>
                  <span className={`text-[11px] font-semibold px-[8px] py-[2px] rounded-full flex-shrink-0 ${MAINTENANCE_STATUS_COLORS[m.status as keyof typeof MAINTENANCE_STATUS_COLORS] ?? 'bg-slate-100 text-slate-500'}`}>
                    {MAINTENANCE_STATUS_LABELS[m.status as keyof typeof MAINTENANCE_STATUS_LABELS] ?? m.status}
                  </span>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState, useCallback } from 'react'
import { Plus, ChevronDown, ChevronRight, Play, CheckCheck, X, Package } from 'lucide-react'
import { inventoryApi, unitApi, assetApi, userApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { InventoryResponse, UnitResponse, AssetResponse, UserResponse } from '../../types'
import {
  INVENTORY_STATUS_LABELS, INVENTORY_STATUS_COLORS,
  ASSET_STATUS_LABELS, ASSET_STATUS_COLORS, ASSET_TYPE_LABELS,
  INPUT_CLS, TipButton, ErrorBanner,
  resolveUnitName, resolveUserName, formatDate,
} from '../../shared'

// ─── SessionAssets ────────────────────────────────────────────────────────────

interface SessionAssetsProps {
  unitId: number
  users: UserResponse[]
}

function SessionAssets({ unitId, users }: SessionAssetsProps) {
  const [assets, setAssets] = useState<AssetResponse[]>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    setLoading(true)
    assetApi.list({ unitId, size: 200 })
      .then((p) => setAssets(Array.isArray(p?.content) ? p.content : []))
      .catch(() => setAssets([]))
      .finally(() => setLoading(false))
  }, [unitId])

  if (loading) return <div className="px-6 py-4 text-[12px] text-slate-400">Carregando ativos...</div>
  if (assets.length === 0) return <div className="px-6 py-4 text-[12px] text-slate-400">Nenhum ativo cadastrado nesta unidade.</div>

  return (
    <div className="border-t border-slate-100">
      <div className="px-4 py-2 bg-slate-50 flex items-center gap-2">
        <Package size={12} className="text-slate-400" />
        <span className="text-[11px] font-bold text-slate-400 uppercase tracking-wider">
          {assets.length} ativo{assets.length !== 1 ? 's' : ''}
        </span>
      </div>
      <table className="w-full border-collapse">
        <thead>
          <tr className="bg-slate-50 border-b border-slate-100">
            {['Tag', 'Modelo', 'Tipo', 'Status', 'Responsável'].map((h) => (
              <th key={h} className="px-4 py-2 text-left text-[10.5px] font-bold text-slate-400 uppercase tracking-wider">{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {assets.map((a) => (
            <tr key={a.id} className="border-b border-slate-50 hover:bg-slate-50 transition">
              <td className="px-4 py-[9px] font-mono text-[12px] text-blue-700 font-semibold">{a.assetTag}</td>
              <td className="px-4 py-[9px] text-[12.5px] text-slate-700">{a.model}</td>
              <td className="px-4 py-[9px] text-[12px] text-slate-500">{ASSET_TYPE_LABELS[a.type] ?? a.type}</td>
              <td className="px-4 py-[9px]">
                <span className={`text-[11px] font-semibold px-[8px] py-[3px] rounded-full ${ASSET_STATUS_COLORS[a.status as keyof typeof ASSET_STATUS_COLORS] ?? 'bg-slate-100 text-slate-500'}`}>
                  {ASSET_STATUS_LABELS[a.status as keyof typeof ASSET_STATUS_LABELS] ?? a.status}
                </span>
              </td>
              <td className="px-4 py-[9px] text-[12px] text-slate-500">
                {resolveUserName(a.assignedUserId, users)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  )
}

// ─── InventoryPage ────────────────────────────────────────────────────────────

export default function InventoryPage() {
  const { user, isGestor } = useAuth()
  const [sessions, setSessions] = useState<InventoryResponse[]>([])
  const [units, setUnits] = useState<UnitResponse[]>([])
  const [users, setUsers] = useState<UserResponse[]>([])
  const [loading, setLoading] = useState(true)
  const [expanded, setExpanded] = useState<number | null>(null)
  const [showCreate, setShowCreate] = useState(false)
  const [unitId, setUnitId] = useState('')
  const [saving, setSaving] = useState(false)
  const [actionError, setActionError] = useState('')

  const load = useCallback(() => {
    setLoading(true)
    inventoryApi.list()
      .then((list) => setSessions(Array.isArray(list) ? list : []))
      .catch(() => setSessions([]))
      .finally(() => setLoading(false))
  }, [])

  useEffect(() => { load() }, [load])

  useEffect(() => {
    if (!user?.organizationId) return

    unitApi.listByOrg(user.organizationId)
      .then((list) => {
        const active = Array.isArray(list) ? list.filter((u) => u.status === 'ACTIVE') : []
        setUnits(isGestor && user.unitId ? active.filter((u) => u.id === user.unitId) : active)
      })
      .catch(() => setUnits([]))

    userApi.list({ size: 200 })
      .then((p) => setUsers(Array.isArray(p?.content) ? p.content : []))
      .catch(() => setUsers([]))
  }, [user?.organizationId])

  const handleCreate = async () => {
    if (!unitId) return
    setSaving(true)
    setActionError('')
    try {
      await inventoryApi.create(Number(unitId))
      setShowCreate(false)
      setUnitId('')
      load()
    } catch (e: any) {
      setActionError(e?.response?.data?.error?.message ?? e?.response?.data?.message ?? 'Erro ao criar sessão')
    } finally {
      setSaving(false)
    }
  }

  const handleAction = async (fn: () => Promise<any>, label: string) => {
    if (saving) return
    setSaving(true)
    setActionError('')
    try {
      await fn()
      load()
    } catch (e: any) {
      setActionError(e?.response?.data?.error?.message ?? e?.response?.data?.message ?? `Erro ao ${label}`)
    } finally {
      setSaving(false)
    }
  }

  const availableUnits = units.filter(
    (u) => !sessions.some((s) => s.unitId === u.id && (s.status === 'OPEN' || s.status === 'IN_PROGRESS'))
  )
  const blockedUnitsCount = units.length - availableUnits.length

  const stats = {
    total: sessions.length,
    open: sessions.filter((s) => s.status === 'OPEN').length,
    inProgress: sessions.filter((s) => s.status === 'IN_PROGRESS').length,
    closed: sessions.filter((s) => s.status === 'CLOSED').length,
  }

  if (loading) {
    return <div className="flex items-center justify-center h-64 text-slate-400">Carregando...</div>
  }

  return (
    <div>
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">Inventário</h1>
          <p className="text-[13px] text-slate-500 mt-1">Conferência de ativos por unidade</p>
        </div>
        <button
          onClick={() => { setUnitId(''); setActionError(''); setShowCreate(true) }}
          className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition">
          <Plus size={14} /> Nova Sessão
        </button>
      </div>

      <ErrorBanner message={actionError} onDismiss={() => setActionError('')} />

      <div className="grid grid-cols-4 gap-[14px] mb-5">
        {[
          { label: 'Total', val: stats.total, color: '' },
          { label: 'Abertos', val: stats.open, color: 'text-blue-600' },
          { label: 'Em Andamento', val: stats.inProgress, color: 'text-amber-600' },
          { label: 'Fechadas', val: stats.closed, color: 'text-emerald-600' },
        ].map((c) => (
          <div key={c.label} className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm">
            <div className={`text-[24px] font-bold ${c.color}`}>{c.val}</div>
            <div className="text-[12px] text-slate-400 mt-1">{c.label}</div>
          </div>
        ))}
      </div>

      <div className="bg-white rounded-[10px] border border-slate-200 shadow-sm overflow-hidden">
        {sessions.length === 0 ? (
          <div className="text-center py-12 text-slate-400">Nenhuma sessão de inventário encontrada</div>
        ) : (
          sessions.map((s) => (
            <div key={s.id} className="border-b border-slate-100 last:border-0">
              <div
                className="flex items-center gap-3 px-4 py-3 hover:bg-slate-50 transition cursor-pointer"
                onClick={() => setExpanded(expanded === s.id ? null : s.id)}
              >
                <div className="text-slate-400 flex-shrink-0">
                  {expanded === s.id ? <ChevronDown size={15} /> : <ChevronRight size={15} />}
                </div>

                <div className="flex-1 grid grid-cols-4 gap-4 items-center">
                  <div>
                    <div className="text-[13.5px] font-semibold text-slate-800">
                      {resolveUnitName(s.unitId, units)}
                    </div>
                    <div className="text-[11px] text-slate-400 mt-[1px]">
                      Criado em {formatDate(s.createdAt)}
                    </div>
                  </div>

                  <div>
                    <span className={`text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full ${
                      INVENTORY_STATUS_COLORS[s.status as keyof typeof INVENTORY_STATUS_COLORS] ?? 'bg-slate-100 text-slate-500'
                    }`}>
                      {INVENTORY_STATUS_LABELS[s.status as keyof typeof INVENTORY_STATUS_LABELS] ?? s.status}
                    </span>
                  </div>

                  <div className="text-[12px] text-slate-500">
                    {s.closedAt ? `Fechado em ${formatDate(s.closedAt)}` : '—'}
                  </div>

                  <div />
                </div>

                <div className="flex gap-[5px]" onClick={(e) => e.stopPropagation()}>
                  {s.status === 'OPEN' && (
                    <TipButton tip="Iniciar contagem" onClick={() => handleAction(() => inventoryApi.start(s.id), 'iniciar')}>
                      <Play size={13} />
                    </TipButton>
                  )}
                  {s.status === 'IN_PROGRESS' && (
                    <TipButton tip="Fechar sessão" onClick={() => handleAction(() => inventoryApi.close(s.id), 'fechar')}>
                      <CheckCheck size={13} />
                    </TipButton>
                  )}
                  {['OPEN', 'IN_PROGRESS'].includes(s.status) && (
                    <TipButton tip="Cancelar sessão" danger onClick={() => handleAction(() => inventoryApi.cancel(s.id), 'cancelar')}>
                      <X size={13} />
                    </TipButton>
                  )}
                </div>
              </div>

              {expanded === s.id && <SessionAssets unitId={s.unitId} users={users} />}
            </div>
          ))
        )}
      </div>

      {/* Modal nova sessão */}
      {showCreate && (
        <div
          className="fixed inset-0 bg-slate-900/50 z-50 flex items-center justify-center p-5"
          onClick={(e) => e.target === e.currentTarget && setShowCreate(false)}
        >
          <div className="bg-white rounded-[14px] w-full max-w-[420px] shadow-2xl">
            <div className="flex justify-between items-center px-6 pt-5 pb-0">
              <h2 className="text-[17px] font-bold">Nova Sessão de Inventário</h2>
              <button
                onClick={() => setShowCreate(false)}
                className="w-7 h-7 rounded-[6px] border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-slate-50"
              >
                ✕
              </button>
            </div>

            <div className="px-6 py-5 space-y-[14px]">
              <div>
                <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-[.4px] mb-[6px]">
                  Unidade *
                </label>

                {units.length === 0 ? (
                  <p className="text-[12px] text-slate-400">Carregando unidades...</p>
                ) : availableUnits.length === 0 ? (
                  <p className="text-[12.5px] text-amber-700 bg-amber-50 border border-amber-200 rounded-[7px] px-3 py-2">
                    Todas as unidades já possuem sessão de inventário aberta.
                  </p>
                ) : (
                  <div>
                    <select
                      value={unitId}
                      onChange={(e) => setUnitId(e.target.value)}
                      className={INPUT_CLS}
                    >
                      <option value="">Selecione uma unidade...</option>
                      {availableUnits.map((u) => (
                        <option key={u.id} value={u.id}>{u.name}</option>
                      ))}
                    </select>
                    {blockedUnitsCount > 0 && (
                      <p className="text-[11.5px] text-slate-400 mt-[6px]">
                        {blockedUnitsCount} unidade{blockedUnitsCount > 1 ? 's' : ''} ocultada{blockedUnitsCount > 1 ? 's' : ''} — já possui sessão aberta.
                      </p>
                    )}
                  </div>
                )}
              </div>

              <div className="flex gap-2 justify-end pt-2 border-t border-slate-100">
                <button
                  onClick={() => { setShowCreate(false); setActionError('') }}
                  className="px-4 py-[8px] rounded-[8px] border-[1.5px] border-slate-200 text-[13px] font-semibold hover:bg-slate-50"
                >
                  Cancelar
                </button>
                <button
                  onClick={handleCreate}
                  disabled={saving || !unitId}
                  className="px-4 py-[8px] rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 disabled:opacity-50"
                >
                  {saving ? 'Criando...' : 'Criar Sessão'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useEffect, useState, useCallback } from 'react'
import { useSearchParams } from 'react-router-dom'
import { Plus, Play, CheckCheck, X } from 'lucide-react'
import { maintenanceApi, assetApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { MaintenanceResponse, MaintenanceBudget, MaintenanceStatus, Page, AssetResponse } from '../../types'
import {
  MAINTENANCE_STATUS_LABELS, MAINTENANCE_STATUS_COLORS,
  TipButton, Pagination, ErrorBanner, formatCurrency, resolveAssetLabel, formatCode,
} from '../../shared'
import { CreateMaintenanceModal } from './components/CreateMaintenanceModal'
import { CompleteMaintenanceModal } from './components/CompleteMaintenanceModal'

const VALID_STATUSES = ['ALL', 'REQUESTED', 'IN_PROGRESS', 'COMPLETED', 'CANCELLED']

type StatusFilterValue = MaintenanceStatus | 'ALL' | 'OPEN'

export default function MaintenancePage() {
  const [searchParams] = useSearchParams()
  const { user, isAdmin, isGestor } = useAuth()

  const urlUnitId = searchParams.get('unitId') ? Number(searchParams.get('unitId')) : undefined
  const urlAssignedUserId = searchParams.get('assignedUserId') ? Number(searchParams.get('assignedUserId')) : undefined

  const effectiveUnitId = urlUnitId ?? (!isAdmin && isGestor ? user?.unitId : undefined)
  const effectiveAssignedUserId = urlAssignedUserId ?? (!isAdmin && !isGestor ? user?.userId : undefined)

  const urlStatus = searchParams.get('status')
  const initialStatus: StatusFilterValue =
    urlStatus === 'OPEN' ? 'OPEN'
    : urlStatus && VALID_STATUSES.includes(urlStatus) ? urlStatus as MaintenanceStatus
    : 'ALL'

  const [page, setPage] = useState<Page<MaintenanceResponse> | null>(null)
  const [budget, setBudget] = useState<MaintenanceBudget | null>(null)
  const [statusFilter, setStatusFilter] = useState<StatusFilterValue>(initialStatus)
  const [currentPage, setCurrentPage] = useState(0)
  const [loading, setLoading] = useState(true)

  const [showCreate, setShowCreate] = useState(false)
  const [showComplete, setShowComplete] = useState<MaintenanceResponse | null>(null)

  const [assetList, setAssetList] = useState<AssetResponse[]>([])

  const [form, setForm] = useState({ assetId: '', description: '', estimatedCost: '' })
  const [descError, setDescError] = useState('')

  const [completeForm, setCompleteForm] = useState({ resolution: '', actualCost: '' })
  const [resolveError, setResolveError] = useState('')

  const [saving, setSaving] = useState(false)
  const [actionLoadingId, setActionLoadingId] = useState<number | null>(null)
  const [actionError, setActionError] = useState('')

  useEffect(() => {
    assetApi.list({
      size: 500,
      ...(effectiveUnitId ? { unitId: effectiveUnitId } : {}),
      ...(effectiveAssignedUserId ? { assignedUserId: effectiveAssignedUserId } : {}),
    })
      .then((p) => setAssetList(Array.isArray(p?.content) ? p.content : []))
      .catch(console.error)
  }, [effectiveUnitId, effectiveAssignedUserId])

  const load = useCallback(() => {
    setLoading(true)

    const apiStatus: MaintenanceStatus | undefined =
      statusFilter === 'ALL' || statusFilter === 'OPEN'
        ? undefined
        : statusFilter

    Promise.all([
      maintenanceApi.list({
        page: currentPage,
        size: 20,
        sort: 'createdAt,desc',
        ...(apiStatus ? { status: apiStatus } : {}),
        ...(effectiveUnitId ? { unitId: effectiveUnitId } : {}),
        ...(effectiveAssignedUserId ? { requestedByUserId: effectiveAssignedUserId } : {}),
      }),
      (isAdmin || isGestor)
        ? maintenanceApi.getBudget({
            ...(effectiveUnitId ? { unitId: effectiveUnitId } : {}),
          })
        : Promise.resolve(null),
    ])
      .then(([p, b]) => {
        if (statusFilter === 'OPEN' && p?.content) {
          const filtered = p.content.filter(
            (m) => m.status === 'REQUESTED' || m.status === 'IN_PROGRESS'
          )
          setPage({ ...p, content: filtered, totalElements: filtered.length })
        } else {
          setPage(p ?? null)
        }
        setBudget(b ?? null)
      })
      .catch(console.error)
      .finally(() => setLoading(false))
  }, [currentPage, statusFilter, effectiveUnitId, effectiveAssignedUserId])

  useEffect(() => { load() }, [load])

  const handleCreate = async () => {
    if (!form.assetId) return
    if (form.description.length < 10) {
      setDescError('Descrição deve ter no mínimo 10 caracteres')
      return
    }
    if (form.description.length > 1000) {
      setDescError('Descrição deve ter no máximo 1000 caracteres')
      return
    }
    setSaving(true)
    setActionError('')
    try {
      const parsedEstimated = form.estimatedCost
        ? Number(form.estimatedCost.replace(/[R$\s.]/g, '').replace(',', '.'))
        : undefined
      await maintenanceApi.create({
        assetId: Number(form.assetId),
        description: form.description,
        ...(parsedEstimated !== undefined && parsedEstimated > 0 ? { estimatedCost: parsedEstimated } : {}),
      })
      setShowCreate(false)
      load()
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ?? e?.response?.data?.message ?? 'Erro ao abrir ordem'
      )
    } finally { setSaving(false) }
  }

  const handleComplete = async () => {
    if (!showComplete) return
    const trimmedRes = completeForm.resolution.trim()
    if (trimmedRes.length < 10) {
      setResolveError('Descreva a resolução com pelo menos 10 caracteres')
      return
    }
    setSaving(true)
    setActionError('')
    setResolveError('')
    try {
      const parsedCost = completeForm.actualCost
        ? Number(completeForm.actualCost.replace(/[R$\s.]/g, '').replace(',', '.'))
        : undefined
      await maintenanceApi.complete(showComplete.id, trimmedRes, parsedCost)
      setShowComplete(null)
      load()
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ?? e?.response?.data?.message ?? 'Erro ao concluir manutenção'
      )
    } finally { setSaving(false) }
  }

  const handleStart = async (m: MaintenanceResponse) => {
    setActionLoadingId(m.id)
    setActionError('')
    try {
      await maintenanceApi.start(m.id)
      load()
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ?? e?.response?.data?.message ?? 'Erro ao iniciar'
      )
    } finally { setActionLoadingId(null) }
  }

  const handleCancel = async (m: MaintenanceResponse) => {
    if (!confirm(`Cancelar a manutenção ${formatCode('MNT', m.id)}?`)) return
    setActionLoadingId(m.id)
    setActionError('')
    try {
      await maintenanceApi.cancel(m.id)
      load()
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ?? e?.response?.data?.message ?? 'Erro ao cancelar'
      )
    } finally { setActionLoadingId(null) }
  }

  return (
    <div>
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">Manutenção</h1>
          <p className="text-[13px] text-slate-500 mt-1">
            {effectiveAssignedUserId
              ? 'Ordens de serviço relacionadas a você'
              : effectiveUnitId
              ? 'Ordens de serviço da sua unidade'
              : 'Controle de ordens de serviço e orçamento'}
          </p>
        </div>
        <button
          data-testid="maintenance-open-order-btn"
          onClick={() => {
            setForm({ assetId: '', description: '', estimatedCost: '' })
            setDescError('')
            setActionError('')
            setShowCreate(true)
          }}
          className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition"
        >
          <Plus size={14} /> Abrir Ordem
        </button>
      </div>

      <ErrorBanner message={actionError} onDismiss={() => setActionError('')} />

      {budget && (
        <div className="grid grid-cols-3 gap-[14px] mb-5">
          <div className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm">
            <div className="text-[11px] text-slate-400 uppercase tracking-[.5px] mb-2">Total de ordens</div>
            <div className="text-[22px] font-bold text-slate-800">{budget.totalRecords}</div>
            <div className="text-[11.5px] text-slate-400 mt-1">
              {budget.completedRecords} concluída{budget.completedRecords !== 1 ? 's' : ''}
              {budget.totalRecords > 0 && (
                <span className="ml-1">({Math.round((budget.completedRecords / budget.totalRecords) * 100)}%)</span>
              )}
            </div>
          </div>
          <div className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm">
            <div className="text-[11px] text-slate-400 uppercase tracking-[.5px] mb-2">Custo estimado</div>
            {budget.totalEstimatedCost > 0 ? (
              <>
                <div className="text-[22px] font-bold text-slate-800">{formatCurrency(budget.totalEstimatedCost)}</div>
                <div className="text-[11.5px] text-slate-400 mt-1">soma das ordens abertas</div>
              </>
            ) : (
              <>
                <div className="text-[18px] font-semibold text-slate-300">—</div>
                <div className="text-[11.5px] text-slate-400 mt-1">nenhuma estimativa informada</div>
              </>
            )}
          </div>
          <div className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm">
            <div className="text-[11px] text-slate-400 uppercase tracking-[.5px] mb-2">Custo real</div>
            {budget.totalActualCost > 0 ? (
              <>
                <div className={`text-[22px] font-bold ${
                  budget.totalEstimatedCost > 0 && budget.totalActualCost > budget.totalEstimatedCost
                    ? 'text-red-600'
                    : budget.totalEstimatedCost > 0
                    ? 'text-emerald-600'
                    : 'text-slate-800'
                }`}>
                  {formatCurrency(budget.totalActualCost)}
                </div>
                <div className="text-[11.5px] text-slate-400 mt-1">
                  {budget.totalEstimatedCost > 0
                    ? budget.totalActualCost > budget.totalEstimatedCost
                      ? `${formatCurrency(budget.totalActualCost - budget.totalEstimatedCost)} acima do estimado`
                      : `${formatCurrency(budget.totalEstimatedCost - budget.totalActualCost)} abaixo do estimado`
                    : `${budget.completedRecords} ordem(ns) concluída(s)`}
                </div>
              </>
            ) : (
              <>
                <div className="text-[18px] font-semibold text-slate-300">—</div>
                <div className="text-[11.5px] text-slate-400 mt-1">nenhum custo registrado</div>
              </>
            )}
          </div>
        </div>
      )}

      <div className="bg-white rounded-[10px] border border-slate-200 overflow-hidden shadow-sm">
        <div className="flex gap-[6px] px-4 py-[10px] border-b border-slate-100 flex-wrap">
          {(['ALL', 'REQUESTED', 'IN_PROGRESS', 'COMPLETED', 'CANCELLED'] as const).map((s) => (
            <button
              key={s}
              data-testid={`maintenance-status-filter-${String(s).toLowerCase()}`}
              onClick={() => { setStatusFilter(s); setCurrentPage(0) }}
              className={`px-3 py-1 rounded-full text-[12px] font-medium border-[1.5px] transition ${
                statusFilter === s
                  ? 'bg-blue-100 text-blue-700 border-blue-500'
                  : 'bg-white text-slate-500 border-slate-200 hover:border-blue-400'
              }`}
            >
              {s === 'ALL' ? 'Todas' : MAINTENANCE_STATUS_LABELS[s]}
            </button>
          ))}
        </div>

        <div className="overflow-x-auto">
          <table className="w-full border-collapse">
            <thead className="bg-slate-50">
              <tr>
                {['Código', 'Ativo', 'Descrição', 'Status', 'Criada em', 'Ações'].map((h) => (
                  <th key={h} className="px-[14px] py-[10px] text-left text-[11px] font-bold text-slate-400 uppercase tracking-[.5px] border-b border-slate-200">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan={6} className="text-center py-12 text-slate-400">Carregando...</td></tr>
              ) : (page?.content ?? []).length === 0 ? (
                <tr><td colSpan={6} className="text-center py-12 text-slate-400">Nenhuma ordem encontrada</td></tr>
              ) : (page?.content ?? []).map((m) => (
                <tr key={m.id} data-testid="maintenance-row" className="hover:bg-slate-50 transition-colors">
                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <span className="font-mono text-[12px] text-blue-700">{formatCode('MNT', m.id)}</span>
                  </td>
                  <td className="px-[14px] py-3 border-b border-slate-50 text-[13px] text-slate-600">
                    {resolveAssetLabel(m.assetId, assetList)}
                  </td>
                  <td className="px-[14px] py-3 border-b border-slate-50 text-[13px] max-w-[240px] truncate" title={m.description}>
                    {m.description}
                  </td>
                  <td className="px-[14px] py-3 border-b border-slate-50">
                          <span className={`text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full ${
                            MAINTENANCE_STATUS_COLORS[m.status as keyof typeof MAINTENANCE_STATUS_COLORS] ?? 'bg-slate-100 text-slate-500'
                          }`}>
                            {MAINTENANCE_STATUS_LABELS[m.status as keyof typeof MAINTENANCE_STATUS_LABELS] ?? m.status}
                          </span>
                        </td>
                  <td className="px-[14px] py-3 border-b border-slate-50 text-[13px] text-slate-500">
                    {new Date(m.createdAt).toLocaleDateString('pt-BR')}
                  </td>
                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <div className="flex gap-[5px]">
                      {m.status === 'REQUESTED' && (
                        <TipButton testId="maintenance-action-start" tip="Iniciar" loading={actionLoadingId === m.id} onClick={() => handleStart(m)}>
                          <Play size={13} />
                        </TipButton>
                      )}
                      {m.status === 'IN_PROGRESS' && (
                        <TipButton testId="maintenance-action-complete" tip="Concluir" onClick={() => {
                          setCompleteForm({ resolution: '', actualCost: '' })
                          setShowComplete(m)
                        }}>
                          <CheckCheck size={13} />
                        </TipButton>
                      )}
                      {['REQUESTED', 'IN_PROGRESS'].includes(m.status) && (
                        <TipButton testId="maintenance-action-cancel" tip="Cancelar" danger loading={actionLoadingId === m.id} onClick={() => handleCancel(m)}>
                          <X size={13} />
                        </TipButton>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {page && (
          <Pagination
            currentPage={currentPage}
            totalPages={page.totalPages}
            totalElements={page.totalElements}
            pageSize={20}
            isFirst={page.first}
            isLast={page.last}
            onPageChange={setCurrentPage}
            currentCount={page.content.length}
          />
        )}
      </div>

      <CreateMaintenanceModal
        open={showCreate}
        onClose={() => setShowCreate(false)}
        assets={assetList}
        form={form}
        setForm={setForm}
        descError={descError}
        setDescError={setDescError}
        onConfirm={handleCreate}
        saving={saving}
        actionError={actionError}
      />

      <CompleteMaintenanceModal
        maintenance={showComplete}
        onClose={() => setShowComplete(null)}
        assets={assetList}
        form={completeForm}
        setForm={setCompleteForm}
        resolveError={resolveError}
        setResolveError={setResolveError}
        onConfirm={handleComplete}
        saving={saving}
        actionError={actionError}
      />
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Building2, Pencil, X, Check } from 'lucide-react'
import { organizationApi, unitApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { OrganizationResponse, UnitResponse } from '../../types'
import { INPUT_CLS, ErrorBanner } from '../../shared'

// ─── Linha de informação ──────────────────────────────────────────────────────
function InfoRow({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <div className="text-[10.5px] text-slate-400 uppercase tracking-[.4px] mb-1 font-semibold">
        {label}
      </div>
      <div className="text-[14px] font-semibold text-slate-800">{value}</div>
    </div>
  )
}

// ─── Página ───────────────────────────────────────────────────────────────────
export default function OrganizationsPage() {
  const { user } = useAuth()

  const [org, setOrg] = useState<OrganizationResponse | null>(null)
  const [units, setUnits] = useState<UnitResponse[]>([])
  const [loading, setLoading] = useState(true)
  const [loadError, setLoadError] = useState('')

  // edição do nome
  const [editing, setEditing] = useState(false)
  const [editName, setEditName] = useState('')
  const [saving, setSaving] = useState(false)
  const [saveError, setSaveError] = useState('')
  const [saveSuccess, setSaveSuccess] = useState(false)

  useEffect(() => {
    if (!user?.organizationId) return

    setLoading(true)
    setLoadError('')

    Promise.all([
      organizationApi.getById(user.organizationId),
      unitApi.listByOrg(user.organizationId),
    ])
      .then(([o, u]) => {
        setOrg(o)
        setUnits(Array.isArray(u) ? u : [])
      })
      .catch(() => setLoadError('Erro ao carregar informações da organização'))
      .finally(() => setLoading(false))
  }, [user?.organizationId])

  const openEdit = () => {
    if (!org) return
    setEditName(org.name)
    setSaveError('')
    setSaveSuccess(false)
    setEditing(true)
  }

  const cancelEdit = () => {
    setEditing(false)
    setSaveError('')
  }

  const handleSave = async () => {
    const trimmed = editName.trim()
    if (!trimmed || !org) return

    setSaving(true)
    setSaveError('')
    setSaveSuccess(false)

    try {
      await organizationApi.updateName(org.id, trimmed)
      setOrg((prev) => prev ? { ...prev, name: trimmed } : prev)
      setEditing(false)
      setSaveSuccess(true)
      setTimeout(() => setSaveSuccess(false), 3000)
    } catch (e: any) {
      setSaveError(
        e?.response?.data?.message ?? 'Erro ao atualizar nome da organização'
      )
    } finally {
      setSaving(false)
    }
  }

  // Estatísticas de unidades
  const totalUnits = units.length
  const activeUnits = units.filter((u: UnitResponse) => u.status === 'ACTIVE').length
  const inactiveUnits = totalUnits - activeUnits

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64 text-slate-400">
        Carregando...
      </div>
    )
  }

  return (
    <div>
      {/* Cabeçalho */}
      <div className="mb-6">
        <h1 className="text-[20px] font-bold tracking-tight">Organização</h1>
        <p className="text-[13px] text-slate-500 mt-1">
          Informações e configurações da organização
        </p>
      </div>

      <ErrorBanner message={loadError} onDismiss={() => setLoadError('')} />

      {org && (
        <>
          {/* Card principal */}
          <div className="bg-white rounded-[12px] border border-slate-200 shadow-sm overflow-hidden mb-5">
            {/* Header do card */}
            <div className="flex items-center gap-4 px-6 py-5 border-b border-slate-100">
              <div className="w-12 h-12 rounded-[10px] bg-blue-100 flex items-center justify-center flex-shrink-0">
                <Building2 size={22} className="text-blue-700" />
              </div>
              <div className="flex-1 min-w-0">
                {editing ? (
                  <div className="flex items-center gap-2">
                    <input
                      value={editName}
                      onChange={(e) => setEditName(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') handleSave()
                        if (e.key === 'Escape') cancelEdit()
                      }}
                      maxLength={100}
                      autoFocus
                      className="flex-1 border-[1.5px] border-blue-400 rounded-[7px] px-3 py-[7px] text-[15px] font-semibold outline-none bg-white focus:ring-2 focus:ring-blue-100 transition"
                    />
                    <button
                      onClick={handleSave}
                      disabled={saving || !editName.trim()}
                      title="Salvar"
                      className="w-8 h-8 rounded-[6px] bg-blue-700 text-white flex items-center justify-center hover:bg-blue-800 transition disabled:opacity-50"
                    >
                      {saving
                        ? <span className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
                        : <Check size={14} />
                      }
                    </button>
                    <button
                      onClick={cancelEdit}
                      title="Cancelar"
                      className="w-8 h-8 rounded-[6px] border border-slate-200 text-slate-500 flex items-center justify-center hover:bg-slate-50 transition"
                    >
                      <X size={14} />
                    </button>
                  </div>
                ) : (
                  <div className="flex items-center gap-2 group">
                    <span className="text-[17px] font-bold text-slate-900 truncate">
                      {org.name}
                    </span>
                    <button
                      onClick={openEdit}
                      title="Editar nome"
                      className="opacity-0 group-hover:opacity-100 w-7 h-7 rounded-[6px] border border-slate-200 text-slate-400 flex items-center justify-center hover:bg-slate-50 hover:text-slate-700 transition"
                    >
                      <Pencil size={13} />
                    </button>
                  </div>
                )}
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[11.5px] font-semibold px-[8px] py-[2px] rounded-full bg-emerald-100 text-emerald-700">
                    Ativa
                  </span>
                </div>
              </div>
            </div>

            {/* Campos de informação */}
            <div className="grid grid-cols-3 gap-6 px-6 py-5">
              <InfoRow label="Total de unidades" value={String(totalUnits)} />
              <InfoRow label="Unidades ativas" value={String(activeUnits)} />
              <InfoRow label="Unidades inativas" value={String(inactiveUnits)} />
            </div>
          </div>

          {/* Tabela original INTACTA */}
          <div className="bg-white rounded-[12px] border border-slate-200 shadow-sm overflow-hidden">
            <div className="px-6 py-4 border-b border-slate-100">
              <h2 className="text-[14px] font-bold text-slate-800">
                Unidades vinculadas
              </h2>
              <p className="text-[12px] text-slate-400 mt-[2px]">
                Para gerenciar unidades, acesse o menu <strong>Unidades</strong>.
              </p>
            </div>

            <table className="w-full border-collapse">
              <thead className="bg-slate-50">
                <tr>
                  {['Nome', 'Tipo', 'Status'].map((h) => (
                    <th
                      key={h}
                      className="px-[14px] py-[10px] text-left text-[11px] font-bold text-slate-400 uppercase tracking-[.5px] border-b border-slate-200"
                    >
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {units.length === 0 ? (
                  <tr>
                    <td colSpan={3} className="text-center py-10 text-slate-400 text-[13px]">
                      Nenhuma unidade cadastrada
                    </td>
                  </tr>
                ) : (
                  units.map((u: UnitResponse) => (
                    <tr key={u.id} className="hover:bg-slate-50 transition">
                      <td className="px-[14px] py-3 border-b border-slate-50">
                        <span className="text-[13.5px] font-semibold text-slate-800">
                          {u.name}
                        </span>
                      </td>
                      <td className="px-[14px] py-3 border-b border-slate-50">
                        {u.mainUnit ? (
                          <span className="text-[11.5px] font-semibold px-[8px] py-[2px] rounded-full bg-blue-100 text-blue-700">
                            Matriz
                          </span>
                        ) : (
                          <span className="text-[12px] text-slate-400">Filial</span>
                        )}
                      </td>
                      <td className="px-[14px] py-3 border-b border-slate-50">
                        <span
                          className={`text-[11.5px] font-semibold px-[8px] py-[2px] rounded-full ${
                            u.status === 'ACTIVE'
                              ? 'bg-emerald-100 text-emerald-700'
                              : 'bg-slate-100 text-slate-500'
                          }`}
                        >
                          {u.status === 'ACTIVE' ? 'Ativa' : 'Inativa'}
                        </span>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { FileDown, Package, Wrench, Shield } from 'lucide-react'
import { exportApi, depreciationApi } from '../../api'
import type { PortfolioDepreciation } from '../../types'
import {
  DateRangeFilter,
  DepreciationBar,
  formatCurrency,
  ErrorBanner,
} from '../../shared'

export default function ReportsPage() {
  const [startDate, setStartDate] = useState('')
  const [endDate, setEndDate] = useState('')

  const [portfolio, setPortfolio] = useState<PortfolioDepreciation | null>(null)
  const [loadingPortfolio, setLoadingPortfolio] = useState(true)

  const [exporting, setExporting] = useState<string | null>(null)
  const [error, setError] = useState('')

  useEffect(() => {
    setLoadingPortfolio(true)

    depreciationApi
      .getPortfolio()
      .then((data) => setPortfolio(data ?? null))
      .catch(() => {
        // Gestor pode não ter permissão ou não haver dados — não exibir erro, apenas sem dados
        setPortfolio(null)
      })
      .finally(() => setLoadingPortfolio(false))
  }, [])

  const dateError =
    startDate && endDate && endDate < startDate
      ? 'A data final deve ser posterior à data inicial'
      : ''

  const handleExport = async (type: string, fn: () => Promise<any>) => {
    if (exporting) return

    setExporting(type)
    setError('')

    try {
      await fn()
    } catch (e: any) {
      setError(
        e?.response?.data?.message ??
        'Erro ao exportar relatório'
      )
    } finally {
      setExporting(null)
    }
  }

  const reports = [
    {
      key: 'assets',
      title: 'Exportar Ativos',
      desc: 'Todos os ativos com status, unidade, responsável e tipo.',
      icon: <Package size={20} />,
      color: 'bg-blue-100 text-blue-700',
      fn: () => exportApi.downloadAssets(startDate || undefined, endDate || undefined),
    },
    {
      key: 'maintenance',
      title: 'Exportar Manutenções',
      desc: 'Ordens de serviço com filtro de período.',
      icon: <Wrench size={20} />,
      color: 'bg-amber-100 text-amber-700',
      fn: () => exportApi.downloadMaintenance(startDate || undefined, endDate || undefined),
    },
    {
      key: 'audit',
      title: 'Exportar Auditoria',
      desc: 'Log de eventos com filtro de período.',
      icon: <Shield size={20} />,
      color: 'bg-purple-100 text-purple-700',
      fn: () => exportApi.downloadAudit(startDate || undefined, endDate || undefined),
    },
  ]

  return (
    <div>
      <div className="mb-5">
        <h1 className="text-[20px] font-bold tracking-tight">
          Relatórios e Exportações
        </h1>
        <p className="text-[13px] text-slate-500 mt-1">
          Exporte dados em CSV por módulo
        </p>
      </div>

      <ErrorBanner message={error} onDismiss={() => setError('')} />

      {/* Filtro */}
      <div className="flex gap-3 items-end mb-6 bg-white rounded-[10px] border border-slate-200 p-4 shadow-sm flex-wrap">
        <span className="text-[13px] font-semibold text-slate-600">
          Período:
        </span>

        <DateRangeFilter
          startDate={startDate}
          endDate={endDate}
          onStartChange={setStartDate}
          onEndChange={setEndDate}
          onClear={() => {
            setStartDate('')
            setEndDate('')
          }}
          error={dateError}
        />
      </div>

      {/* Cards */}
      <div className="grid grid-cols-3 gap-[14px] mb-6">
        {reports.map((r) => (
          <div
            key={r.key}
            className="bg-white rounded-[10px] border border-slate-200 p-[22px] shadow-sm hover:shadow-md transition-all"
          >
            <div className={`w-11 h-11 rounded-[10px] flex items-center justify-center mb-4 ${r.color}`}>
              {r.icon}
            </div>

            <div className="text-[14px] font-bold mb-[6px]">
              {r.title}
            </div>

            <div className="text-[12.5px] text-slate-400 leading-relaxed mb-4">
              {r.desc}
            </div>

            <div className="flex justify-end">
              <button
                onClick={() => handleExport(r.key, r.fn)}
                disabled={!!dateError || exporting !== null}
                className="flex items-center gap-2 px-3 py-[6px] rounded-[7px] bg-blue-700 text-white text-[12px] font-semibold hover:bg-blue-800 transition disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {exporting === r.key ? (
                  <>
                    <span className="w-3 h-3 border-2 border-white border-t-transparent rounded-full animate-spin" />
                    Exportando...
                  </>
                ) : (
                  <>
                    <FileDown size={12} /> Baixar CSV
                  </>
                )}
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* Depreciação */}
      <div className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm">
        <h3 className="text-[13.5px] font-bold mb-4">
          Depreciação do Portfólio
        </h3>

        {loadingPortfolio ? (
          <div className="text-center py-6 text-slate-400">
            Carregando...
          </div>
        ) : !portfolio ? (
          <div className="text-center py-6 text-slate-400">
            Nenhum dado disponível
          </div>
        ) : (
          <>
            <div className="grid grid-cols-4 gap-4 mb-4">
              {[
                { label: 'Valor de Compra', val: formatCurrency(portfolio.totalPurchaseValue), color: '' },
                { label: 'Valor Atual', val: formatCurrency(portfolio.totalCurrentValue), color: 'text-blue-700' },
                { label: 'Total Depreciado', val: formatCurrency(portfolio.totalDepreciation), color: 'text-red-600' },
                { label: '% Depreciado', val: `${portfolio.depreciationPercentage.toFixed(1)}%`, color: 'text-amber-600' },
              ].map((f) => (
                <div key={f.label}>
                  <div className="text-[11px] text-slate-400 uppercase tracking-[.4px] mb-1">
                    {f.label}
                  </div>
                  <div className={`text-[18px] font-bold ${f.color}`}>
                    {f.val}
                  </div>
                </div>
              ))}
            </div>

            <DepreciationBar depreciationPercentage={portfolio.depreciationPercentage} />

            <div className="text-[11.5px] text-slate-400 mt-1">
              {portfolio.totalAssets} ativos no portfólio
            </div>
          </>
        )}
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { useSearchParams } from 'react-router-dom'
import { Plus } from 'lucide-react'
import { transferApi, assetApi, unitApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { TransferResponse, AssetResponse, UnitResponse, TransferStatus } from '../../types'
import {
  TRANSFER_STATUS_LABELS,
  TRANSFER_STATUS_COLORS,
  resolveUnitName,
  formatCode,
  formatDate,
  ErrorBanner,
} from '../../shared'
import { TransferDetail } from './components/TransferDetail'
import { CreateTransferModal } from './components/CreateTransferModal'

const PAGE_SIZE = 20

const TRANSFER_STATUS_FILTERS: Array<{ label: string; value: TransferStatus | 'ALL' }> = [
  { label: 'Todos', value: 'ALL' },
  { label: 'Pendente', value: 'PENDING' },
  { label: 'Aprovado', value: 'APPROVED' },
  { label: 'Rejeitado', value: 'REJECTED' },
  { label: 'Concluído', value: 'COMPLETED' },
  { label: 'Cancelado', value: 'CANCELLED' },
]

export default function TransfersPage() {
  const [searchParams] = useSearchParams()
  const { user, isGestor, isAdmin } = useAuth()

  const effectiveUnitId = !isAdmin && isGestor ? user?.unitId : undefined

  const [transfers, setTransfers] = useState<TransferResponse[]>([])
  const [selected, setSelected] = useState<TransferResponse | null>(null)
  const [statusFilter, setStatusFilter] = useState<TransferStatus | 'ALL'>('ALL')

  const [loading, setLoading] = useState(true)
  const [transferPage, setTransferPage] = useState(0)
  const [transferTotal, setTransferTotal] = useState(0)

  const [actionLoading, setActionLoading] = useState(false)
  const [actionError, setActionError] = useState('')

  const [allUnits, setAllUnits] = useState<UnitResponse[]>([])
  const [allAssets, setAllAssets] = useState<AssetResponse[]>([])

  const [showCreate, setShowCreate] = useState(false)
  const [modalAssets, setModalAssets] = useState<AssetResponse[]>([])
  const [modalUnits, setModalUnits] = useState<UnitResponse[]>([])

  const [form, setForm] = useState({
    assetId: '',
    toUnitId: '',
    reason: '',
  })

  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [reasonError, setReasonError] = useState('')

  useEffect(() => {
    if (!user?.organizationId) return

    unitApi
      .listByOrg(user.organizationId)
      .then((list) => setAllUnits(Array.isArray(list) ? list : []))
      .catch(console.error)

    assetApi
      .list({
        size: 500,
        ...(effectiveUnitId ? { unitId: effectiveUnitId } : {}),
      })
      .then((p) =>
        setAllAssets(Array.isArray(p?.content) ? p.content : [])
      )
      .catch(console.error)
  }, [user?.organizationId, effectiveUnitId])

  const load = (pg = transferPage, selectFirst = false) => {
    setLoading(true)

    transferApi
      .list({
        page: pg,
        size: PAGE_SIZE,
        sort: 'requestedAt,desc',
        ...(statusFilter !== 'ALL' ? { status: statusFilter } : {}),
        ...(effectiveUnitId ? { unitId: effectiveUnitId } : {}),
      })
      .then((p) => {
        const content = Array.isArray(p?.content) ? p.content : []

        setTransfers(content)
        setTransferTotal(p?.totalElements ?? 0)

        if (content.length) {
          const stillExists = selectFirst
            ? undefined
            : content.find((t) => t.id === selected?.id)
          setSelected(stillExists ?? content[0])
        } else {
          setSelected(null)
        }
      })
      .catch(console.error)
      .finally(() => setLoading(false))
  }

  useEffect(() => {
    load(0)
  }, [statusFilter])

  useEffect(() => {
    load(transferPage)
  }, [transferPage])

  const openCreate = () => {
    setError('')
    setReasonError('')
    setForm({ assetId: '', toUnitId: '', reason: '' })

    Promise.all([
      assetApi.list({ size: 100, status: 'AVAILABLE' }),
      user?.organizationId
        ? unitApi.listByOrg(user.organizationId)
        : Promise.resolve([]),
    ])
      .then(([ap, ul]) => {
        setModalAssets(
          Array.isArray(ap?.content) ? ap.content : []
        )
        setModalUnits(Array.isArray(ul) ? ul : [])
      })
      .catch(console.error)

    setShowCreate(true)
  }

  const handleCreate = async () => {
    if (!form.assetId || !form.toUnitId) return

    const trimmedReason = form.reason.trim()

    if (trimmedReason.length < 10) {
      setReasonError(
        'Descreva o motivo com pelo menos 10 caracteres'
      )
      return
    }

    setSaving(true)
    setError('')
    setReasonError('')

    try {
      await transferApi.create({
        assetId: Number(form.assetId),
        toUnitId: Number(form.toUnitId),
        reason: trimmedReason,
      })

      setShowCreate(false)
      load(0, true)
    } catch (e: any) {
      setError(
        e?.response?.data?.error?.message ??
          e?.response?.data?.message ??
          'Erro ao criar solicitação'
      )
    } finally {
      setSaving(false)
    }
  }

  const handleAction = async (
    fn: () => Promise<any>,
    label: string
  ) => {
    setActionError('')
    setActionLoading(true)

    try {
      await fn()
      load(transferPage)
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ??
          e?.response?.data?.message ??
          `Erro ao ${label}`
      )
    } finally {
      setActionLoading(false)
    }
  }

  return (
    <div>
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">
            Transferências
          </h1>
          <p className="text-[13px] text-slate-500 mt-1">
            Movimentações de ativos entre unidades
          </p>
        </div>

        <button
          data-testid="transfer-new-request-btn"
          type="button"
          onClick={openCreate}
          className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition"
        >
          <Plus size={14} /> Nova Solicitação
        </button>
      </div>

      <ErrorBanner
        message={actionError}
        onDismiss={() => setActionError('')}
      />

      <div className="flex gap-[6px] px-4 py-[10px] border-b border-slate-100 flex-wrap items-center">
        {TRANSFER_STATUS_FILTERS.map((f) => (
          <button
            key={f.value}
            data-testid={`transfer-status-filter-${String(f.value).toLowerCase()}`}
            onClick={() => { setStatusFilter(f.value); setTransferPage(0) }}
            className={`px-3 py-1 rounded-full text-[12px] font-medium border-[1.5px] transition ${
              statusFilter === f.value
                ? 'bg-blue-100 text-blue-700 border-blue-500'
                : 'bg-white text-slate-500 border-slate-200 hover:border-blue-400'
            }`}
          >
            {f.label}{f.value === 'ALL' ? ` (${transferTotal})` : ''}
          </button>
        ))}
      </div>

      <div
        className="flex rounded-[10px] border border-slate-200 bg-white overflow-hidden shadow-sm"
        style={{ height: 'calc(100vh - 190px)' }}
      >
        <div className="w-[290px] min-w-[290px] border-r border-slate-200 flex flex-col">
          <div className="p-[14px] border-b border-slate-100">
            <div className="font-bold text-[14px]">
              Transferências
            </div>
            <div className="text-[11.5px] text-slate-500 mt-[2px]">
              {
                transfers.filter(
                  (t) => t.status === 'PENDING'
                ).length
              }{' '}
              aguardando aprovação
            </div>
          </div>

          <div className="flex-1 overflow-y-auto">
            {loading ? (
              <div className="text-center py-10 text-slate-400 text-[13px]">
                Carregando...
              </div>
            ) : (
              transfers.map((t: TransferResponse) => (
                <div
                  key={t.id}
                  data-testid="transfer-card"
                  onClick={() => setSelected(t)}
                  className={`px-[14px] py-3 border-b border-slate-50 cursor-pointer transition border-l-[3px] ${
                    selected?.id === t.id
                      ? 'bg-blue-50 border-l-blue-700'
                      : 'border-l-transparent hover:bg-slate-50'
                  }`}
                >
                  <div className="flex justify-between items-start mb-[5px]">
                    <span className="font-mono text-[12.5px] text-blue-700 font-bold">
                      {formatCode('TRF', t.id)}
                    </span>

                    <span
                      className={`text-[11px] font-semibold px-[8px] py-[2px] rounded-full ${
                        TRANSFER_STATUS_COLORS[t.status as keyof typeof TRANSFER_STATUS_COLORS] ??
                        'bg-slate-100 text-slate-500'
                      }`}
                    >
                      {TRANSFER_STATUS_LABELS[t.status as keyof typeof TRANSFER_STATUS_LABELS] ??
                        t.status}
                    </span>
                  </div>

                  <div className="text-[11.5px] text-slate-400">
                    {resolveUnitName(
                      t.fromUnitId,
                      allUnits
                    )}{' '}
                    →{' '}
                    {resolveUnitName(
                      t.toUnitId,
                      allUnits
                    )}
                  </div>

                  <div className="text-[11px] text-slate-300 mt-1">
                    {formatDate(t.requestedAt)}
                  </div>
                </div>
              ))
            )}
          </div>

          {transferTotal > PAGE_SIZE && (
            <div className="flex items-center justify-between px-3 py-2 border-t border-slate-100 flex-shrink-0">
              <span className="text-[10.5px] text-slate-400">
                {transferTotal} total
              </span>

              <div className="flex gap-1 items-center">
                <button
                  type="button"
                  disabled={transferPage === 0}
                  onClick={() =>
                    setTransferPage((p) => p - 1)
                  }
                  className="w-6 h-6 rounded border border-slate-200 text-slate-500 text-[11px] flex items-center justify-center hover:bg-slate-50 disabled:opacity-40"
                >
                  ‹
                </button>

                <span className="text-[11px] text-slate-500 px-1">
                  {transferPage + 1}/
                  {Math.ceil(transferTotal / PAGE_SIZE)}
                </span>

                <button
                  type="button"
                  disabled={
                    (transferPage + 1) * PAGE_SIZE >=
                    transferTotal
                  }
                  onClick={() =>
                    setTransferPage((p) => p + 1)
                  }
                  className="w-6 h-6 rounded border border-slate-200 text-slate-500 text-[11px] flex items-center justify-center hover:bg-slate-50 disabled:opacity-40"
                >
                  ›
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="flex-1 p-5 overflow-y-auto">
          {!selected ? (
            <div className="flex items-center justify-center h-full text-slate-400 text-[13px]">
              Selecione uma transferência
            </div>
          ) : (
            <TransferDetail
              selected={selected}
              allUnits={allUnits}
              allAssets={allAssets}
              isAdmin={isAdmin}
              isGestor={isGestor}
              actionLoading={actionLoading}
              onAction={handleAction}
            />
          )}
        </div>
      </div>

      <CreateTransferModal
        open={showCreate}
        onClose={() => setShowCreate(false)}
        assets={modalAssets}
        units={modalUnits}
        form={form}
        setForm={setForm}
        reasonError={reasonError}
        setReasonError={setReasonError}
        error={error}
        onConfirm={handleCreate}
        saving={saving}
      />
    </div>
  )
}

import { CheckCircle, XCircle, Check, Ban } from 'lucide-react'
import { transferApi } from '../../../api'
import type { TransferResponse, TransferStatus, UnitResponse, AssetResponse } from '../../../types'
import {
  TRANSFER_STATUS_LABELS,
  TRANSFER_STATUS_COLORS,
  resolveUnitName,
  resolveAssetLabel,
  formatCode,
  formatDate,
} from '../../../shared'

interface TransferDetailProps {
  selected: TransferResponse
  allUnits: UnitResponse[]
  allAssets: AssetResponse[]
  isAdmin: boolean
  isGestor: boolean
  actionLoading: boolean
  onAction: (fn: () => Promise<any>, label: string) => void
}

const progressSteps: Array<{ label: string; dateKey: keyof TransferResponse }> = [
  { label: 'Solicitado', dateKey: 'requestedAt' },
  { label: 'Aprovado',   dateKey: 'approvedAt' },
  { label: 'Recebido',   dateKey: 'completedAt' },
]

function getProgressIndex(status: TransferStatus) {
  if (status === 'COMPLETED') return 2
  if (status === 'APPROVED')  return 1
  return 0
}

export function TransferDetail({
  selected, allUnits, allAssets, isAdmin, isGestor, actionLoading, onAction,
}: TransferDetailProps) {
  const progress = getProgressIndex(selected.status)
  const lineWidth = progress === 0 ? '0%' : progress === 1 ? '50%' : '100%'

  return (
    <>
      <div className="border border-slate-200 rounded-[10px] p-[18px] mb-4">
        <div className="flex justify-between items-start mb-3">
          <div>
            <div className="text-[17px] font-bold">{formatCode('TRF', selected.id)}</div>
            <div className="text-[12.5px] text-slate-500 mt-[2px]">
              Solicitado em {formatDate(selected.requestedAt)}
            </div>
          </div>
          <span className={`text-[11.5px] font-semibold px-3 py-[4px] rounded-full ${
            TRANSFER_STATUS_COLORS[selected.status] ?? 'bg-slate-100 text-slate-500'
          }`}>
            {TRANSFER_STATUS_LABELS[selected.status] ?? selected.status}
          </span>
        </div>

        <div className="grid grid-cols-3 gap-3 mt-3">
          <div>
            <label className="block text-[10.5px] text-slate-400 uppercase tracking-[.4px] mb-1">Origem</label>
            <span className="text-[13px] font-semibold">{resolveUnitName(selected.fromUnitId, allUnits)}</span>
          </div>
          <div>
            <label className="block text-[10.5px] text-slate-400 uppercase tracking-[.4px] mb-1">Destino</label>
            <span className="text-[13px] font-semibold">{resolveUnitName(selected.toUnitId, allUnits)}</span>
          </div>
          <div>
            <label className="block text-[10.5px] text-slate-400 uppercase tracking-[.4px] mb-1">Ativo</label>
            <span className="font-mono text-[12px] text-blue-700">{resolveAssetLabel(selected.assetId, allAssets)}</span>
          </div>
        </div>

        {selected.reason && (
          <div className="mt-3 pt-3 border-t border-slate-100">
            <label className="block text-[10.5px] text-slate-400 uppercase tracking-[.4px] mb-1">Motivo</label>
            <p className="text-[13px] text-slate-600">{selected.reason}</p>
          </div>
        )}
      </div>

      {selected.status === 'PENDING' && (
        <div className="flex gap-2 mb-4">
          {(isAdmin || isGestor) && (
            <>
              <button type="button" data-testid="transfer-detail-approve-btn" disabled={actionLoading}
                onClick={() => onAction(() => transferApi.approve(selected.id), 'aprovar')}
                className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-emerald-600 text-white text-[13px] font-semibold hover:bg-emerald-700 transition disabled:opacity-50">
                <CheckCircle size={14} /> {actionLoading ? 'Processando...' : 'Aprovar Transferência'}
              </button>
              <button type="button" data-testid="transfer-detail-reject-btn" disabled={actionLoading}
                onClick={() => onAction(() => transferApi.reject(selected.id), 'rejeitar')}
                className="flex items-center gap-2 px-4 py-2 rounded-[8px] border-[1.5px] border-red-200 text-red-600 text-[13px] font-semibold hover:bg-red-50 transition disabled:opacity-50">
                <XCircle size={14} /> Rejeitar
              </button>
            </>
          )}
          <button type="button" data-testid="transfer-detail-cancel-btn" disabled={actionLoading}
            onClick={() => onAction(() => transferApi.cancel(selected.id), 'cancelar')}
            className="flex items-center gap-2 px-4 py-2 rounded-[8px] border-[1.5px] border-slate-200 text-slate-500 text-[13px] font-semibold hover:bg-slate-50 transition disabled:opacity-50">
            <Ban size={14} /> Cancelar
          </button>
        </div>
      )}

      {selected.status === 'APPROVED' && (
        <div className="flex gap-2 mb-4">
          <button type="button" data-testid="transfer-detail-complete-btn" disabled={actionLoading}
            onClick={() => onAction(() => transferApi.complete(selected.id), 'completar')}
            className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition disabled:opacity-50">
            <Check size={14} /> {actionLoading ? 'Processando...' : 'Confirmar Recebimento'}
          </button>
        </div>
      )}

      {/* Progress bar — usa layout flex para não ultrapassar limites */}
      <div className="border border-slate-200 rounded-[10px] p-[18px]">
        <h3 className="text-[13.5px] font-bold mb-6">Progresso</h3>

        <div className="flex items-center">
          {progressSteps.map((step, i) => {
            const dateVal = selected[step.dateKey] as string | undefined
            const done = i < progress
            const current = i === progress && selected.status !== 'REJECTED' && selected.status !== 'CANCELLED'

            return (
              <div key={i} className="flex items-center flex-1 last:flex-none">
                {/* Step circle */}
                <div className="flex flex-col items-center">
                  <div className={`w-[36px] h-[36px] rounded-full border-[2.5px] flex items-center justify-center flex-shrink-0 transition ${
                    done    ? 'bg-emerald-500 border-emerald-500'
                    : current ? 'bg-blue-700 border-blue-700'
                    :           'bg-white border-slate-200'
                  }`}>
                    {done
                      ? <Check size={14} className="text-white" />
                      : <span className={`text-[12px] font-bold ${current ? 'text-white' : 'text-slate-400'}`}>{i + 1}</span>
                    }
                  </div>
                  <div className="text-[11.5px] font-semibold text-center text-slate-600 mt-[7px] whitespace-nowrap">
                    {step.label}
                  </div>
                  {dateVal && (
                    <div className="text-[10.5px] text-slate-400 text-center mt-[2px]">
                      {formatDate(dateVal)}
                    </div>
                  )}
                </div>

                {/* Connector line between steps */}
                {i < progressSteps.length - 1 && (
                  <div className="flex-1 h-[2px] bg-slate-200 mx-3 relative top-[-16px]">
                    {i < progress && (
                      <div className="h-full bg-emerald-500 w-full" />
                    )}
                  </div>
                )}
              </div>
            )
          })}
        </div>

        {selected.status === 'REJECTED' && (
          <div className="mt-4 bg-red-50 border border-red-200 rounded-[8px] p-3 text-[12.5px] text-red-700 text-center">
            Esta transferência foi <strong>rejeitada</strong>.
          </div>
        )}
        {selected.status === 'CANCELLED' && (
          <div className="mt-4 bg-slate-50 border border-slate-200 rounded-[8px] p-3 text-[12.5px] text-slate-500 text-center">
            Esta transferência foi <strong>cancelada</strong>.
          </div>
        )}
      </div>
    </>
  )
}

import { useEffect, useState, useCallback } from 'react'
import { Plus, MapPin, CheckCircle, XCircle } from 'lucide-react'
import { unitApi, organizationApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { UnitResponse, OrganizationResponse } from '../../types'
import { INPUT_CLS, ErrorBanner } from '../../shared'

export default function UnitsPage() {
  const { user } = useAuth()

  const [units, setUnits] = useState<UnitResponse[]>([])
  const [org, setOrg] = useState<OrganizationResponse | null>(null)

  const [loading, setLoading] = useState(true)
  const [showCreate, setShowCreate] = useState(false)

  const [name, setName] = useState('')
  const [saving, setSaving] = useState(false)

  const [error, setError] = useState('')
  const [toggleError, setToggleError] = useState('')
  const [loadError, setLoadError] = useState('')

  const [togglingId, setTogglingId] = useState<number | null>(null)

  const load = useCallback(() => {
    if (user?.organizationId == null) return

    setLoading(true)
    setLoadError('')

    Promise.all([
      unitApi.listByOrg(user.organizationId),
      organizationApi.getById(user.organizationId),
    ])
      .then(([u, o]) => {
        setUnits(Array.isArray(u) ? u : [])
        setOrg(o ?? null)
      })
      .catch((e: any) => {
        console.error(e)
        setUnits([])
        setOrg(null)
        setLoadError('Erro ao carregar unidades')
      })
      .finally(() => setLoading(false))
  }, [user?.organizationId])

  useEffect(() => {
    load()
  }, [load])

  const handleCreate = async () => {
    if (!name.trim() || user?.organizationId == null) return

    setSaving(true)
    setError('')

    try {
      await unitApi.create(user.organizationId, name.trim())

      setName('')
      setShowCreate(false)
      load()
    } catch (e: any) {
      setError(
        e?.response?.data?.message ??
        'Erro ao criar unidade'
      )
    } finally {
      setSaving(false)
    }
  }

  const handleToggle = async (unit: UnitResponse) => {
    setTogglingId(unit.id)
    setToggleError('')

    try {
      if (unit.status === 'ACTIVE') {
        await unitApi.inactivate(unit.id)
      } else {
        await unitApi.activate(unit.id)
      }

      load()
    } catch (e: any) {
      setToggleError(
        e?.response?.data?.error?.message ??
        e?.response?.data?.message ??
        'Erro ao alterar status'
      )
    } finally {
      setTogglingId(null)
    }
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">
            Unidades
          </h1>
          <p className="text-[13px] text-slate-400 mt-[2px]">
            {org
              ? `Organização: ${org.name}`
              : 'Unidades da sua organização'}
          </p>
        </div>

        <button
          onClick={() => {
            if (!user?.organizationId) return
            setName('')
            setError('')
            setShowCreate(true)
          }}
          disabled={!user?.organizationId}
          className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition disabled:opacity-50"
        >
          <Plus size={14} /> Nova Unidade
        </button>
      </div>

      <ErrorBanner message={loadError} onDismiss={() => setLoadError('')} />
      <ErrorBanner message={toggleError} onDismiss={() => setToggleError('')} />

      {loading ? (
        <div className="text-center py-20 text-slate-400">
          Carregando...
        </div>
      ) : (
        <div className="bg-white rounded-[10px] border border-slate-200 overflow-hidden shadow-sm">
          <table className="w-full border-collapse">
            <thead className="bg-slate-50">
              <tr>
                {['Nome', 'Principal', 'Status', 'Ações'].map((h) => (
                  <th
                    key={h}
                    className="px-[14px] py-[10px] text-left text-[11px] font-bold text-slate-400 uppercase tracking-[.5px] border-b border-slate-200"
                  >
                    {h}
                  </th>
                ))}
              </tr>
            </thead>

            <tbody>
              {units.length === 0 ? (
                <tr>
                  <td colSpan={4} className="text-center py-10 text-slate-400">
                    Nenhuma unidade cadastrada
                  </td>
                </tr>
              ) : (
                units.map((unit) => (
                  <tr key={unit.id} className="hover:bg-slate-50 transition">

                    <td className="px-[14px] py-3 border-b border-slate-100">
                      <div className="flex items-center gap-2">
                        <MapPin size={14} className="text-blue-600" />
                        <span className="text-[13.5px] font-semibold">
                          {unit.name}
                        </span>
                      </div>
                    </td>

                    <td className="px-[14px] py-3 border-b border-slate-100">
                      {unit.mainUnit ? (
                        <span className="text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full bg-blue-100 text-blue-700">
                          Matriz
                        </span>
                      ) : (
                        <span className="text-[11.5px] text-slate-400">
                          Filial
                        </span>
                      )}
                    </td>

                    <td className="px-[14px] py-3 border-b border-slate-100">
                      <span
                        className={`text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full ${
                          unit.status === 'ACTIVE'
                            ? 'bg-emerald-100 text-emerald-700'
                            : 'bg-slate-100 text-slate-500'
                        }`}
                      >
                        {unit.status === 'ACTIVE' ? 'Ativa' : 'Inativa'}
                      </span>
                    </td>

                    <td className="px-[14px] py-3 border-b border-slate-100">
                      <button
                        onClick={() => handleToggle(unit)}
                        disabled={unit.mainUnit || togglingId === unit.id}
                        title={
                          unit.mainUnit
                            ? 'Não é possível inativar a unidade principal'
                            : undefined
                        }
                        className={`flex items-center gap-1 px-3 py-[6px] rounded-[7px] text-[12px] font-semibold border transition disabled:opacity-40 disabled:cursor-not-allowed ${
                          unit.status === 'ACTIVE'
                            ? 'border-slate-200 text-slate-600 hover:bg-slate-50'
                            : 'border-emerald-200 text-emerald-700 hover:bg-emerald-50'
                        }`}
                      >
                        {togglingId === unit.id ? (
                          <>
                            <span className="w-3 h-3 border-2 border-current border-t-transparent rounded-full animate-spin inline-block" />
                            Aguarde...
                          </>
                        ) : unit.status === 'ACTIVE' ? (
                          <>
                            <XCircle size={13} /> Inativar
                          </>
                        ) : (
                          <>
                            <CheckCircle size={13} /> Ativar
                          </>
                        )}
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}

      {/* Modal */}
      {showCreate && (
        <div
          className="fixed inset-0 bg-slate-900/50 z-50 flex items-center justify-center p-5"
          onClick={(e) =>
            e.target === e.currentTarget && setShowCreate(false)
          }
        >
          <div className="bg-white rounded-[14px] w-full max-w-[420px] shadow-2xl">
            <div className="flex justify-between items-center px-6 pt-5 pb-0">
              <h2 className="text-[17px] font-bold">
                Nova Unidade
              </h2>

              <button
                onClick={() => setShowCreate(false)}
                className="w-7 h-7 rounded-[6px] border border-slate-200 flex items-center justify-center text-slate-400 hover:bg-slate-50"
              >
                ✕
              </button>
            </div>

            <div className="px-6 py-5">
              <div className="mb-4">
                <label className="block text-[11px] font-semibold text-slate-500 uppercase tracking-[.4px] mb-[6px]">
                  Nome *
                </label>

                <input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  onKeyDown={(e) =>
                    e.key === 'Enter' && handleCreate()
                  }
                  maxLength={100}
                  placeholder="Ex: Filial SP"
                  className={INPUT_CLS}
                  autoFocus
                />

                {error && (
                  <p className="text-[12px] text-red-500 mt-1">
                    {error}
                  </p>
                )}
              </div>

              <div className="flex gap-2 justify-end pt-2 border-t border-slate-100">
                <button
                  onClick={() => setShowCreate(false)}
                  className="px-4 py-[8px] rounded-[8px] border-[1.5px] border-slate-200 text-[13px] font-semibold text-slate-700 hover:bg-slate-50 transition"
                >
                  Cancelar
                </button>

                <button
                  onClick={handleCreate}
                  disabled={saving || !name.trim()}
                  className="px-4 py-[8px] rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {saving ? 'Criando...' : 'Criar'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Mail, Lock, UserMinus, UserCheck, Plus } from 'lucide-react'
import { userApi, unitApi } from '../../api'
import { useAuth } from '../../context/AuthContext'
import type { UserResponse, UserRole, UnitResponse } from '../../types'
import {
  USER_STATUS_LABELS, USER_STATUS_COLORS, USER_ROLE_LABELS, USER_ROLE_COLORS,
  TipButton, Pagination, ErrorBanner, resolveUnitName,
} from '../../shared'
import { CreateUserModal } from './components/CreateUserModal'
import { useUsers } from '../../hooks/useUsers'

type UserForm = {
  name: string
  email: string
  documentNumber: string
  role: string
  unitId: string
  organizationId: string
  phoneNumber: string
}

function maskCPF(raw: string) {
  const d = raw.replace(/\D/g, '').slice(0, 14)
  if (d.length <= 11)
    return d.replace(/(\d{3})(\d{0,3})(\d{0,3})(\d{0,2})/, (_, a, b, c, dd) =>
      [a, b, c, dd].filter(Boolean).join('.').replace(/\.([^.]+)$/, '-$1')
    )
  return d.replace(/(\d{2})(\d{0,3})(\d{0,3})(\d{0,4})(\d{0,2})/, (_, a, b, c, dd, e) =>
    `${a}.${b}.${c}/${dd}-${e}`
  )
}

function maskPhone(raw: string) {
  const d = raw.replace(/\D/g, '').slice(0, 11)
  if (d.length <= 10)
    return d.replace(/(\d{0,2})(\d{0,4})(\d{0,4})/, (_, a, b, c) =>
      a ? `(${a})${b ? ' ' + b : ''}${c ? '-' + c : ''}` : ''
    )
  return d.replace(/(\d{0,2})(\d{0,5})(\d{0,4})/, (_, a, b, c) =>
    a ? `(${a})${b ? ' ' + b : ''}${c ? '-' + c : ''}` : ''
  )
}

export default function UsersPage() {
  const { user } = useAuth()

  const { page, loading, error, activeCount, pendingCount, load } = useUsers()

  const [units, setUnits] = useState<UnitResponse[]>([])
  const [currentPage, setCurrentPage] = useState(0)

  const [showCreate, setShowCreate] = useState(false)
  const [form, setForm] = useState<UserForm>({
    name: '',
    email: '',
    documentNumber: '',
    role: '',
    unitId: '',
    organizationId: '',
    phoneNumber: '',
  })

  const [saving, setSaving] = useState(false)
  const [createError, setCreateError] = useState('')
  const [actionError, setActionError] = useState('')
  const [actionLoadingId, setActionLoadingId] = useState<number | null>(null)
  const [activationLinkInfo, setActivationLinkInfo] = useState<{ email: string; link: string } | null>(null)

  useEffect(() => {
    if (!user?.organizationId) return
    load(currentPage)
  }, [user?.organizationId, currentPage])

  useEffect(() => {
    if (!user?.organizationId) return
    unitApi.listByOrg(user.organizationId)
      .then((list) =>
        setUnits(Array.isArray(list) ? list.filter((u) => u.status === 'ACTIVE') : [])
      )
      .catch(console.error)
  }, [user?.organizationId])

  useEffect(() => {
    if (user?.organizationId) {
      setForm((f) => ({
        ...f,
        organizationId: String(user.organizationId),
      }))
    }
  }, [user?.organizationId])

  const openCreate = () => {
    setCreateError('')
    setForm({
      name: '',
      email: '',
      documentNumber: '',
      role: '',
      unitId: '',
      organizationId: String(user?.organizationId ?? ''),
      phoneNumber: '',
    })
    setShowCreate(true)
  }

  const handleCreate = async () => {
    if (!form.name.trim() || !form.email.trim() || !form.documentNumber || !form.role || !form.unitId) return

    setSaving(true)
    setCreateError('')

    try {
      const rawDoc = form.documentNumber.replace(/\D/g, '')

      const created = await userApi.create({
        name: form.name.trim(),
        email: form.email.trim(),
        documentNumber: rawDoc,
        role: form.role as UserRole,
        unitId: Number(form.unitId),
        organizationId: Number(form.organizationId),
        phoneNumber: form.phoneNumber ? form.phoneNumber.replace(/\D/g, '') : undefined,
      })
      const token = await userApi.generateActivationToken(created.id)
      const link = buildActivationLink(token)
      setActivationLinkInfo({ email: created.email, link })
      await copyActivationLink(link)

      setShowCreate(false)
      load(currentPage)
    } catch (e: any) {
      setCreateError(
        e?.response?.data?.error?.message ??
        e?.response?.data?.message ??
        'Erro ao criar usuário'
      )
    } finally {
      setSaving(false)
    }
  }

  const handleUserAction = async (userId: number, fn: () => Promise<any>) => {
    setActionLoadingId(userId)
    setActionError('')

    try {
      await fn()
      load(currentPage)
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ??
        e?.response?.data?.message ??
        'Erro ao executar ação'
      )
    } finally {
      setActionLoadingId(null)
    }
  }

  const buildActivationLink = (token: string) => {
    const origin = typeof window !== 'undefined' ? window.location.origin : ''
    return `${origin}/activate?token=${token}`
  }

  const copyActivationLink = async (link: string) => {
    try {
      if (typeof navigator === 'undefined' || !navigator.clipboard) return
      await navigator.clipboard.writeText(link)
    } catch {
      // The link remains visible on screen for manual copy.
    }
  }

  const handleResendActivation = async (targetUser: UserResponse) => {
    setActionLoadingId(targetUser.id)
    setActionError('')

    try {
      const token = await userApi.generateActivationToken(targetUser.id)
      const link = buildActivationLink(token)
      setActivationLinkInfo({ email: targetUser.email, link })
      await copyActivationLink(link)
      load(currentPage)
    } catch (e: any) {
      setActionError(
        e?.response?.data?.error?.message ??
        e?.response?.data?.message ??
        'Erro ao reenviar ativação'
      )
    } finally {
      setActionLoadingId(null)
    }
  }

  return (
    <div>
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-[20px] font-bold tracking-tight">Usuários</h1>
          <p className="text-[13px] text-slate-500 mt-1">Gerenciamento de acessos e perfis</p>
        </div>

        <button
          onClick={openCreate}
          className="flex items-center gap-2 px-4 py-2 rounded-[8px] bg-blue-700 text-white text-[13px] font-semibold hover:bg-blue-800 transition"
        >
          <Plus size={14} /> Novo Usuário
        </button>
      </div>

      <ErrorBanner message={error || actionError} onDismiss={() => setActionError('')} />

      {activationLinkInfo && (
        <div className="mb-4 rounded-[10px] border border-emerald-200 bg-emerald-50 p-4">
          <div className="text-[13px] font-semibold text-emerald-800">
            Link de ativação pronto para envio manual
          </div>
          <div className="mt-1 text-[12.5px] text-emerald-700">
            Usuário: {activationLinkInfo.email}
          </div>
          <div className="mt-2 break-all rounded-[8px] bg-white px-3 py-2 text-[12px] text-slate-700">
            {activationLinkInfo.link}
          </div>
          <div className="mt-3 flex gap-2">
            <button
              type="button"
              onClick={() => copyActivationLink(activationLinkInfo.link)}
              className="rounded-[8px] bg-emerald-700 px-3 py-2 text-[12px] font-semibold text-white hover:bg-emerald-800"
            >
              Copiar link
            </button>
            <button
              type="button"
              onClick={() => setActivationLinkInfo(null)}
              className="rounded-[8px] border border-emerald-200 px-3 py-2 text-[12px] font-semibold text-emerald-800 hover:bg-emerald-100"
            >
              Fechar
            </button>
          </div>
        </div>
      )}

      {page && (
        <div className="grid grid-cols-3 gap-[14px] mb-5">
          {[
            { label: 'Total', val: page.totalElements, icon: <UserCheck size={18} />, color: 'bg-blue-100 text-blue-700' },
            { label: 'Ativos', val: activeCount, icon: <UserCheck size={18} />, color: 'bg-emerald-100 text-emerald-700' },
            { label: 'Pendentes de ativação', val: pendingCount, icon: <Mail size={18} />, color: 'bg-amber-100 text-amber-700' },
          ].map((c) => (
            <div key={c.label} className="bg-white rounded-[10px] border border-slate-200 p-[18px] shadow-sm flex items-center gap-4">
              <div className={`w-[42px] h-[42px] rounded-[9px] flex items-center justify-center ${c.color}`}>{c.icon}</div>
              <div>
                <div className="text-[22px] font-bold">{c.val}</div>
                <div className="text-[12px] text-slate-400">{c.label}</div>
              </div>
            </div>
          ))}
        </div>
      )}

      <div className="bg-white rounded-[10px] border border-slate-200 overflow-hidden shadow-sm">
        <div className="w-full">
          <table className="w-full border-collapse">
            <thead className="bg-slate-50">
              <tr>
                {['Nome', 'E-mail', 'Perfil', 'Unidade', 'Status', 'Autenticação 2 fatores', 'Ações'].map((h) => (
                  <th key={h} className="px-[14px] py-[10px] text-left text-[11px] font-bold text-slate-400 uppercase tracking-[.5px] border-b border-slate-200">{h}</th>
                ))}
              </tr>
            </thead>

            <tbody>
              {loading ? (
                <tr><td colSpan={7} className="text-center py-12 text-slate-400">Carregando...</td></tr>
              ) : page?.content?.length === 0 ? (
                <tr><td colSpan={7} className="text-center py-12 text-slate-400">Nenhum usuário encontrado</td></tr>
              ) : page?.content?.map((u: UserResponse) => (
                <tr key={u.id} className="hover:bg-slate-50 transition-colors">

                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <div className="flex items-center gap-2">
                      <div className="w-7 h-7 rounded-full bg-blue-700 flex items-center justify-center text-white font-bold text-[10px]">
                        {u.name ? u.name.slice(0, 2).toUpperCase() : '--'}
                      </div>
                      <span className="text-[13.5px] font-medium">{u.name}</span>
                    </div>
                  </td>

                  <td className="px-[14px] py-3 border-b border-slate-50 text-[13px] text-slate-500">
                    {u.email}
                  </td>

                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <span className={`text-[11.5px] font-bold px-[10px] py-[3px] rounded-full ${USER_ROLE_COLORS[u.role]}`}>
                      {USER_ROLE_LABELS[u.role] ?? u.role}
                    </span>
                  </td>

                  <td className="px-[14px] py-3 border-b border-slate-50 text-[13px] text-slate-500">
                    {resolveUnitName(u.unitId, units)}
                  </td>

                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <span className={`text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full ${USER_STATUS_COLORS[u.status]}`}>
                      {USER_STATUS_LABELS[u.status as keyof typeof USER_STATUS_LABELS]}
                    </span>
                  </td>

                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <span className={`text-[11.5px] font-semibold px-[10px] py-[3px] rounded-full ${u.mfaEnabled ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-400'}`}>
                      {u.mfaEnabled ? 'Ativo' : 'Inativo'}
                    </span>
                  </td>

                  <td className="px-[14px] py-3 border-b border-slate-50">
                    <div className="flex gap-[5px]">

                      {u.status === 'PENDING_ACTIVATION' && (
                        <TipButton tip="Reenviar ativação" loading={actionLoadingId === u.id}
                          onClick={() => handleResendActivation(u)}>
                          <Mail size={13} />
                        </TipButton>
                      )}

                      {u.status === 'ACTIVE' && (
                        <TipButton tip="Bloquear acesso" danger loading={actionLoadingId === u.id}
                          onClick={() => handleUserAction(u.id, () => userApi.block(u.id))}>
                          <Lock size={13} />
                        </TipButton>
                      )}

                      {u.status === 'BLOCKED' && (
                        <TipButton tip="Reativar usuário" loading={actionLoadingId === u.id}
                          onClick={() => handleUserAction(u.id, () => userApi.activate(u.id))}>
                          <UserCheck size={13} />
                        </TipButton>
                      )}

                      {u.status === 'ACTIVE' && (
                        <TipButton tip="Inativar usuário" danger loading={actionLoadingId === u.id}
                          onClick={() => handleUserAction(u.id, () => userApi.inactivate(u.id))}>
                          <UserMinus size={13} />
                        </TipButton>
                      )}

                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {page && (
          <Pagination
            currentPage={currentPage}
            totalPages={page.totalPages}
            totalElements={page.totalElements}
            pageSize={20}
            isFirst={page.first}
            isLast={page.last}
            onPageChange={setCurrentPage}
            currentCount={page.content.length}
          />
        )}
      </div>

      <CreateUserModal
        open={showCreate}
        onClose={() => setShowCreate(false)}
        form={form}
        setForm={setForm}
        units={units}
        onConfirm={handleCreate}
        saving={saving}
        createError={createError}
        maskCPF={maskCPF}
        maskPhone={maskPhone}
      />
    </div>
  )
}

// ─── PageButton ───────────────────────────────────────────────────────────────

interface PageButtonProps {
  label: string
  active?: boolean
  disabled?: boolean
  onClick: () => void
}

function PageButton({ label, active, disabled, onClick }: PageButtonProps) {
  return (
    <button
      type="button"
      onClick={() => {
        if (!disabled) onClick()
      }}
      disabled={disabled}
      className={`w-7 h-7 rounded-[6px] border-[1.5px] text-[12px] font-semibold flex items-center justify-center transition ${
        active
          ? 'bg-blue-700 text-white border-blue-700'
          : 'bg-white text-slate-500 border-slate-200 hover:border-blue-400 disabled:opacity-40'
      }`}
    >
      {label}
    </button>
  )
}

// ─── Pagination ───────────────────────────────────────────────────────────────

interface PaginationProps {
  currentPage: number
  totalPages: number
  totalElements: number
  pageSize: number
  isFirst: boolean
  isLast: boolean
  onPageChange: (page: number) => void
  /** Quantos itens estão sendo exibidos nesta página */
  currentCount?: number
}

/**
 * Paginação com janela deslizante — sempre exibe a página atual no centro.
 * Corrige o bug presente em MaintenancePage e AuditPage onde a janela
 * ficava fixa nos primeiros índices independente da página atual.
 */
export function Pagination({
  currentPage,
  totalPages,
  totalElements,
  pageSize,
  isFirst,
  isLast,
  onPageChange,
  currentCount,
}: PaginationProps) {
  if (totalPages <= 1) return null

  const getRange = (): number[] => {
    if (totalPages <= 5) return Array.from({ length: totalPages }, (_, i) => i)

    const half = 2
    let start = Math.max(0, currentPage - half)
    let end = Math.min(totalPages - 1, currentPage + half)

    if (end - start < 4) {
      if (start === 0) end = Math.min(4, totalPages - 1)
      else start = Math.max(0, end - 4)
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i)
  }

  const range = getRange()

  // FIX: evitar range inválido quando não há dados
  const displayFrom = totalElements === 0 ? 0 : currentPage * pageSize + 1
  const displayTo = Math.min((currentPage + 1) * pageSize, totalElements)

  // FIX: cálculo correto do range exibido
  const from = totalElements === 0
    ? 0
    : currentPage * pageSize + 1

  const to = totalElements === 0
    ? 0
    : currentPage * pageSize + (currentCount ?? pageSize)

  return (
    <div className="flex items-center justify-between px-4 py-[11px] border-t border-slate-100">
      <span className="text-[13px] text-slate-500">
        Exibindo{' '}
        <strong>
          {from}–{Math.min(to, totalElements)}
        </strong>{' '}
        de <strong>{totalElements}</strong>
      </span>

      <div className="flex gap-1">
        <PageButton
          label="‹"
          disabled={isFirst}
          onClick={() => onPageChange(currentPage - 1)}
        />

        {currentPage > 2 && totalPages > 5 && (
          <>
            <PageButton label="1" onClick={() => onPageChange(0)} />
            {currentPage > 3 && (
              <span className="flex items-center px-1 text-slate-400 text-[12px]">…</span>
            )}
          </>
        )}

        {range.map((i) => (
          <PageButton
            key={i}
            label={String(i + 1)}
            active={i === currentPage}
            onClick={() => onPageChange(i)}
          />
        ))}

        {currentPage < totalPages - 3 && totalPages > 5 && (
          <>
            {currentPage < totalPages - 4 && (
              <span className="flex items-center px-1 text-slate-400 text-[12px]">…</span>
            )}
            <PageButton
              label={String(totalPages)}
              onClick={() => onPageChange(totalPages - 1)}
            />
          </>
        )}

        <PageButton
          label="›"
          disabled={isLast}
          onClick={() => onPageChange(currentPage + 1)}
        />
      </div>
    </div>
  )
}
